-- Poems batch 422
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuanqu-3954','狄青复夺衣袄车・尾声','无名氏','元','元曲','yuanqu','','[]','鹤随鸾凤飞还远，人伴贤良志转高。',94,'元曲/yuanqu.json','["鹤随鸾凤飞还远，人伴贤良志转高。", "那将军施躁暴，这将军是勇跃，夺了车扛，取了衣袄。", "昝先锋着箭凿，史牙恰则一刀。", "这狄青恰似活神道，他轻轮着那三尖两刃刚刀，把些个败残军落荒他可都赶去了。", "(下)。"]'),
('yuanqu-3955','狄青复夺衣袄车・赏花时','无名氏','元','元曲','yuanqu','','[]','推我在深涧里登时一命亏，我若到帅府争知他饶过你。',52,'元曲/yuanqu.json','["推我在深涧里登时一命亏，我若到帅府争知他饶过你。", "狄将军英雄有谁及，若我不分一个曲直，必索要别办个是和非。"]'),
('yuanqu-3956','狄青复夺衣袄车・幺篇','无名氏','元','元曲','yuanqu','','[]','常言道湛湛青天不可欺，若顺了人心失了正理。',55,'元曲/yuanqu.json','["常言道湛湛青天不可欺，若顺了人心失了正理。", "天纲是恢恢，若论着狄肯的这武艺，我则待对倒了他这个赖功的贼！(下)。"]'),
('yuanqu-3957','狄青复夺衣袄车・商调/集贤宾','无名氏','元','元曲','yuanqu','','[]','贪慌忙棘针科抓住战衣，杀败了一个小河西。',117,'元曲/yuanqu.json','["贪慌忙棘针科抓住战衣，杀败了一个小河西。", "行不动山岩下歇息，立不住东倒西欹。", "眼张狂手似捞凌，行不动一丝无力。", "那将军相持厮杀对垒，有军来谁敢迎敌！喧天般发喊声，就地凯征鼙。", "名传于世，委实无敌，(正末见科，云)报、报、报！喏(唱)寰中第一。"]'),
('yuanqu-3958','狄青复夺衣袄车・后庭花','无名氏','元','元曲','yuanqu','','[]','杀的那血成河如聚水，死尸骸山岸般堆。',143,'元曲/yuanqu.json','["杀的那血成河如聚水，死尸骸山岸般堆。", "疏林外枪刀响，山坡前战马厮，莫迎敌。", "谁曾见崎岖的山势，高阜处遥望者见一将来的疾。", "雄赳赳将铠甲披，威凛凛战马嘶，红抹额似火焰飞，皂罗袍似雾黑，乌油甲甚整齐，凤翎箭端的直，鹊桦弓偃月起。", "那将军面皮，三尖刀两刃齐。", "人和马走似飞，喝一声如霹雳，唬的人魂魄飞。"]'),
('yuanqu-3959','狄青复夺衣袄车・双雁儿','无名氏','元','元曲','yuanqu','','[]','俺这壁急慌忙扑倒了这云月皂雕旗，把枪刀不撇了，等甚的！咱顾命逃生早回避，他来的雄势威，惜不的甲马催。',50,'元曲/yuanqu.json','["俺这壁急慌忙扑倒了这云月皂雕旗，把枪刀不撇了，等甚的！咱顾命逃生早回避，他来的雄势威，惜不的甲马催。"]'),
('yuanqu-3960','狄青复夺衣袄车・醋葫芦','无名氏','元','元曲','yuanqu','','[]','昝雄那里饮战马，狄青背后随。',50,'元曲/yuanqu.json','["昝雄那里饮战马，狄青背后随。", "昝雄他英名赳赳竖神威，狄将军怒将金镫踢。", "不离子今日，界河的这两岸要相持。"]'),
('yuanqu-3961','狄青复夺衣袄车・醋葫芦','无名氏','元','元曲','yuanqu','','[]','狄青将右手兜，左手推。',49,'元曲/yuanqu.json','["狄青将右手兜，左手推。", "斟量着远近觑个高低，则他那猿猱臂膊使着气力。", "撼山般威势，转回头斜望着昝雄射。"]'),
('yuanqu-3962','狄青复夺衣袄车・醋葫芦','无名氏','元','元曲','yuanqu','','[]','箭着处支楞楞撇了画戟，扑簌簌掉了豹尾。',56,'元曲/yuanqu.json','["箭着处支楞楞撇了画戟，扑簌簌掉了豹尾。", "脑桩的落马马空回，弯着弓插着箭忙整理。", "将一顶紫金冠撞碎，三思台吞满画桃皮。"]'),
('yuanqu-3963','狄青复夺衣袄车・醋葫芦','无名氏','元','元曲','yuanqu','','[]','一个在河道东，一个在临路西。',49,'元曲/yuanqu.json','["一个在河道东，一个在临路西。", "都不曾答话便相持，却便似黑杀神撞着个霹雳鬼。", "枪强刀会，棋逢对手好相持。"]'),
('yuanqu-3964','狄青复夺衣袄车・醋葫芦','无名氏','元','元曲','yuanqu','','[]','史牙恰枪去的疾，狄将军刀去劈。',141,'元曲/yuanqu.json','["史牙恰枪去的疾，狄将军刀去劈。", "刀迎枪举足律律火光飞，见枪来躲过，着刀去劈。", "我则见连肩带臂，恰便似锦毛彪扑倒一个玉狻猊。", "(李滚云)箭射死昝雄，刀劈了史牙恰。", "天朝威风浩大，猛将英雄，再不敢调遣番兵，俺则索投降纳贡。", "便好道饶你深山共深处，到头都属帝王家。", "探子，你且回本营中去。", "(正末唱)。"]'),
('yuanqu-3965','狄青复夺衣袄车・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','我这里步步刚捱，病身躯恰才安泰，行不动东倒西歪。',58,'元曲/yuanqu.json','["我这里步步刚捱，病身躯恰才安泰，行不动东倒西歪。", "脚刚移，身强整，魂灵儿不知个所在。", "也是我运拙时乖，谁承望这一场颇余。"]'),
('yuanqu-3966','狄青复夺衣袄车・醉春风','无名氏','元','元曲','yuanqu','','[]','这怨恨重如山，咱冤仇深似海。',63,'元曲/yuanqu.json','["这怨恨重如山，咱冤仇深似海。", "不走了你个奸浊侥幸赖功贼，黄轸也你畅好是歹、歹！我与你折证的明白，狄青他一心忠孝，搭救他这场灾害。"]'),
('yuanqu-3967','狄青复夺衣袄车・红绣鞋','无名氏','元','元曲','yuanqu','','[]','当日个琼填满东郊南陌，粉妆成殿阁楼台，见一簇番兵拥将来。',94,'元曲/yuanqu.json','["当日个琼填满东郊南陌，粉妆成殿阁楼台，见一簇番兵拥将来。", "狄青在火坑中逃了性命，今日向云阳内受非灾，我救这一个苦相持梁栋材。", "(范仲淹云)谁射死咎雄来？(正末云)是狄青一箭射死昝雄来。", "(唱)。"]'),
('yuanqu-3968','狄青复夺衣袄车・上小楼','无名氏','元','元曲','yuanqu','','[]','一来是时间免灾，二来与将军除害。',64,'元曲/yuanqu.json','["一来是时间免灾，二来与将军除害。", "狄青那里怪眼圆睁，剔竖神眉，怒目张开。", "狄青那里显手策，使气概，英雄慷慨，则他那昝先锋那一场灾害。"]'),
('yuanqu-3969','狄青复夺衣袄车・十二月','无名氏','元','元曲','yuanqu','','[]','那将军其实壮哉，那一会气夯破胸怀。',56,'元曲/yuanqu.json','["那将军其实壮哉，那一会气夯破胸怀。", "史牙恰提枪出阵，狄将军纵马前来。", "狄将军刀起处他如何挣挫，那将军威凛凛英勇身材。"]'),
('yuanqu-3970','狄青复夺衣袄车・尾声','无名氏','元','元曲','yuanqu','','[]','我见来，我见来，杀的那史牙恰无百刂划。',265,'元曲/yuanqu.json','["我见来，我见来，杀的那史牙恰无百刂划。", "想狄将军盖世功劳大，保护着一统山河万万载。", "(范仲淹云)老夫尽知也。", "原来是黄轸混赖狄青的功劳，将黄轸推转杀坏了者！狄青，你听者，为你复夺了衣袄扛车，箭射昝雄，刀劈史牙恰，有此功劳，加你为征西都招讨金吾上将军。", "狄青，你望阙跪者，听圣人的命。", "则因你敢勇相争，凭谋略收捕贼兵。", "真梁栋世之虎将，据英雄天下驰名。", "黄面具千般杀气，乌油甲万道威风。", "野水岭刀斩牙恰，杏子河箭射昝雄。", "施勇烈扬威耀武，秉忠心永镇边庭。", "加你为总都大帅，定家邦天下元戎。", "朝金阙躬身叩首，立乾坤帝业兴隆。", "今日个加官赐赏，保皇图万载升平。"]'),
('yuanqu-3971','吕洞宾桃柳升仙梦・北仙吕/点绛唇','贾仲明','元','元曲','yuanqu','','[]','则为我根脚培埋，长青可爱，枝梢大。',31,'元曲/yuanqu.json','["则为我根脚培埋，长青可爱，枝梢大。", "虽然是土木形骸，茂盛多精彩。"]'),
('yuanqu-3972','吕洞宾桃柳升仙梦・混江龙','贾仲明','元','元曲','yuanqu','','[]','绿阴翠盖，依稀袅娜映楼台。',69,'元曲/yuanqu.json','["绿阴翠盖，依稀袅娜映楼台。", "一任教霜凌雪压，日炙风筛。", "近水柔条多雅趣，临风对月助吟怀。", "我可便更软善，无毒害。", "虽不成神仙之道，也是个梁栋之材。"]'),
('yuanqu-3973','吕洞宾桃柳升仙梦・南东瓯令','贾仲明','元','元曲','yuanqu','','[]','多娇态，甚奇哉，嫩蕊娇香霞映色，风流可喜堪人爱。',45,'元曲/yuanqu.json','["多娇态，甚奇哉，嫩蕊娇香霞映色，风流可喜堪人爱。", "家住在天台侧，刘郎去后瘦如柴，懒插短金钗。"]'),
('yuanqu-3974','吕洞宾桃柳升仙梦・南桂枝香','贾仲明','元','元曲','yuanqu','','[]','多承错爱，深蒙款待。',89,'元曲/yuanqu.json','["多承错爱，深蒙款待。", "则咱这爱恋如山，则咱这恩情似海。", "(末云)因姐姐容貌非常。", "(旦唱)我丰姿艳色，我丰姿艳色，你形端无赛。", "正是桃红柳绿，则愿的四时不改。", "今夜同相会，只怕青春不再来。"]'),
('yuanqu-3975','吕洞宾桃柳升仙梦・北鹊踏枝','贾仲明','元','元曲','yuanqu','','[]','趁良宵静幽哉，愿和谐，柳丝长结就同心，桃腮嫩引惹情怀。',48,'元曲/yuanqu.json','["趁良宵静幽哉，愿和谐，柳丝长结就同心，桃腮嫩引惹情怀。", "谢芳卿又不曾见责，怎能够跨苍鸾同赴瑶台？。"]'),
('yuanqu-3976','吕洞宾桃柳升仙梦・南玉包肚','贾仲明','元','元曲','yuanqu','','[]','今宵爽快，趁一天风清月白。',119,'元曲/yuanqu.json','["今宵爽快，趁一天风清月白。", "(末云)我和姐姐饮几杯酒。", "(旦唱)饮金杯暂且宁耐，乘时遣兴开怀。", "子这春从天上九重来，好向亭心酒漫筛。", "(末云)既如此，咱向亭子上饮酒去。", "(做见吕科)(末云)娇桃不中，咱回去来！(吕醒科，云)小鬼头那里去！(末唱)。"]'),
('yuanqu-3977','吕洞宾桃柳升仙梦・北寄生草','贾仲明','元','元曲','yuanqu','','[]','见师父威严大，神气蔼，唬的我兢兢战战磕头拜。',115,'元曲/yuanqu.json','["见师父威严大，神气蔼，唬的我兢兢战战磕头拜。", "(吕云)你是山妖术怪地鬼么？(末唱)不是山妖地鬼人间怪。", "(吕云)你可是甚么妖精？(末唱)俺则是多年枯木英灵在。", "(吕云)贫道答救度脱你如何？(末唱)若是吾师答救俺苍生，早得超凡入圣登仙界。"]'),
('yuanqu-3978','吕洞宾桃柳升仙梦・南乐安神','贾仲明','元','元曲','yuanqu','','[]','但却离的紫陌，可怜桃柳泼形骸。',47,'元曲/yuanqu.json','["但却离的紫陌，可怜桃柳泼形骸。", "只因俺四季不凋衰，不逐流水东风外。", "超凡，天地也盖载，还了冤家债。"]'),
('yuanqu-3979','吕洞宾桃柳升仙梦・北赚煞','贾仲明','元','元曲','yuanqu','','[]','今日个得遇大罗仙，道德如天大，桃也再不去向阳弄色，我可便送尽行人才放解，也是我命运合该。',100,'元曲/yuanqu.json','["今日个得遇大罗仙，道德如天大，桃也再不去向阳弄色，我可便送尽行人才放解，也是我命运合该。", "谢师父说明白，今日个苦尽甘来，直至长安名姓改。", "你休要没颜落色，休等那霜欺雪盖，愿师父早些儿引度俺到蓬莱！(下)。"]'),
('yuanqu-3980','吕洞宾桃柳升仙梦・北中吕/粉蝶儿','贾仲明','元','元曲','yuanqu','','[]','昨日个秋雨淋漓，舞丹枫萧萧叶坠，听砧声别院凄凄。',53,'元曲/yuanqu.json','["昨日个秋雨淋漓，舞丹枫萧萧叶坠，听砧声别院凄凄。", "荡金风，冷玉器，池荷减翠。", "节令相催，今日个赏重阳登高乐意。"]'),
('yuanqu-3981','吕洞宾桃柳升仙梦・醉春风','贾仲明','元','元曲','yuanqu','','[]','你看那北苑柳添黄，东篱菊放蕊。',47,'元曲/yuanqu.json','["你看那北苑柳添黄，东篱菊放蕊。", "橙黄橘绿蟹初肥，端的美，美。", "我如今家道兴隆，门安户泰，夫荣妻贵。"]'),
('yuanqu-3982','吕洞宾桃柳升仙梦・南好事近','贾仲明','元','元曲','yuanqu','','[]','佳节景相宜，玩赏登高游戏。',223,'元曲/yuanqu.json','["佳节景相宜，玩赏登高游戏。", "园林处处，翻蜀锦落叶纷飞。", "升平盛世，设华筵庆赏重阳会。", "好光阴莫得轻抛，想人生百年有几？(末云)真个好景也！兴儿，看众街坊敢待来也。", "(兴儿云)理会的。", "(陈员外、李大户上，云)众街坊，咱来到秀野园前也。", "兴儿报复去，道俺众街坊都来了也。", "(做报科)(末云)道有请！(做见科)(陈云)柳员外，量俺有何德能，请俺街坊登高？深感厚意。", "(末云)众高亲，想人生白驹过隙，遇此节令，休要孤负。", "只是有劳众位，驱驰到此。", "(陈云)不敢。", "(末唱)。"]'),
('yuanqu-3983','吕洞宾桃柳升仙梦・北上小楼','贾仲明','元','元曲','yuanqu','','[]','众街坊齐来到已，赏重阳秋光佳致。',77,'元曲/yuanqu.json','["众街坊齐来到已，赏重阳秋光佳致。", "我安排果桌杯盘，品物希奇，水陆俱备。", "今日笑吟吟，畅开怀，都教沉醉，乐人间洞天福地。", "(陈云)多蒙款待。", "(做饮酒科)(旦唱)。"]'),
('yuanqu-3984','吕洞宾桃柳升仙梦・南千秋岁','贾仲明','元','元曲','yuanqu','','[]','捧金杯摘取黄花香，散朵朵节令相宜。',74,'元曲/yuanqu.json','["捧金杯摘取黄花香，散朵朵节令相宜。", "笑语声喧，笑语声喧，见这仕女佳人相携。", "登高处，郊原内，我则见管弦声里，胜似春光明媚。", "端的是三秋美景，还家再整筵席。"]'),
('yuanqu-3985','吕洞宾桃柳升仙梦・北上小楼','贾仲明','元','元曲','yuanqu','','[]','见仙长容貌伟，神清秀有气质。',165,'元曲/yuanqu.json','["见仙长容貌伟，神清秀有气质。", "(云云)特来度脱你修行，要你弃了家缘，除免灾危。", "(末唱)你可便度我修行，弃了家缘，免了灾危？(旦云)这先生甚么言语？(末唱)大嫂，由他说。", "俺如今更富贵，年未已，是豪杰之辈，我怎肯弃家缘入山隐退？(吕云)你若跟我出家去，着你寻真采药，访道参玄，遨游阆苑，直到蓬莱，不强如居于尘世？你兀的不死也。", "(旦唱)。"]'),
('yuanqu-3986','吕洞宾桃柳升仙梦・南越恁好','贾仲明','元','元曲','yuanqu','','[]','这先生大叫高呼，你劝修行省气力。',94,'元曲/yuanqu.json','["这先生大叫高呼，你劝修行省气力。", "访蓬莱阆苑，寻真采药，容易躲人间是非，成仙了道寿命期。", "(吕云)你休要呆痴。", "(旦唱)他道俺两口儿休要痴，俺三十岁夫共妻，双双美。", "休要管他，俺今日且向花前沉醉。"]'),
('yuanqu-3987','吕洞宾桃柳升仙梦・北快活三','贾仲明','元','元曲','yuanqu','','[]','今日个受诰敕，做通判到江西，不怠慢莫延迟，咱索离城内。',32,'元曲/yuanqu.json','["今日个受诰敕，做通判到江西，不怠慢莫延迟，咱索离城内。", "(旦唱)。"]'),
('yuanqu-3988','吕洞宾桃柳升仙梦・南红绣鞋','贾仲明','元','元曲','yuanqu','','[]','将行李即便收拾，践程途远路奔驰。',44,'元曲/yuanqu.json','["将行李即便收拾，践程途远路奔驰。", "整纲常免差役，调四季用盐梅。", "仗才智抚黔黎，仗才智抚黔黎。"]'),
('yuanqu-3989','吕洞宾桃柳升仙梦・北尾声','贾仲明','元','元曲','yuanqu','','[]','荷方今圣主恩，俺夫妻受诰敕。',38,'元曲/yuanqu.json','["荷方今圣主恩，俺夫妻受诰敕。", "则愿得一朝任满还乡内，燕乐亲朋齐贺喜。", "(同下)。"]'),
('yuanqu-3990','吕洞宾桃柳升仙梦・北越调/斗鹌鹑','贾仲明','元','元曲','yuanqu','','[]','经了些水远山遥，畅好是天宽地狭。',60,'元曲/yuanqu.json','["经了些水远山遥，畅好是天宽地狭。", "野店生莓，山城噪鸦。", "崎岖长途，奔驰瘦马。", "昏邓邓尘似筛，扑唐唐泥又滑。", "绿水堤边，青山那答。"]'),
('yuanqu-3991','吕洞宾桃柳升仙梦・南诉衷肠','贾仲明','元','元曲','yuanqu','','[]','你道是功名牵挂，早过了夕阳下。',74,'元曲/yuanqu.json','["你道是功名牵挂，早过了夕阳下。", "一带云山似图画，眼巴巴几时得到京华？过山遥路远怎去？他教我心惊胆颤怕。", "如今容颜瘦，倒不如受辛勤还家罢，我如今力困筋乏。"]'),
('yuanqu-3992','吕洞宾桃柳升仙梦・北耍三台','贾仲明','元','元曲','yuanqu','','[]','我对你丁宁话，你不必心惊怕。',94,'元曲/yuanqu.json','["我对你丁宁话，你不必心惊怕。", "你须受了那官诰敕札，(旦云)我则要还家去。", "(末唱)你不去敢有刑法，请夫人鉴察。", "我为官理民莫漫夸，你做夫人富贵受用者。", "你穿上霞帔金冠，你见人呵，那其间敢装幺做大。"]'),
('yuanqu-3993','吕洞宾桃柳升仙梦・南山马客','贾仲明','元','元曲','yuanqu','','[]','胡哨飕的几声那答，见强人一簇，炒闹山下，我心惊腿酸麻。',102,'元曲/yuanqu.json','["胡哨飕的几声那答，见强人一簇，炒闹山下，我心惊腿酸麻。", "(末云)夫人，你休要怕，按下心胆。", "(旦唱)唬得我如痴似诤，眼花，(邦云)那里去？(旦唱)几乎唬杀。", "料他不肯放咱，相公，你依我者，俺则索停骖，下马告他。"]'),
('yuanqu-3994','吕洞宾桃柳升仙梦・北调笑令','贾仲明','元','元曲','yuanqu','','[]','太保你鉴察，问根芽，(邦云)你那里人氏？(末唱)俺是那长安富贵家。',104,'元曲/yuanqu.json','["太保你鉴察，问根芽，(邦云)你那里人氏？(末唱)俺是那长安富贵家。", "(邦云)你因何到我这山中？(末唱)我受皇恩理民明教化，为通判俸禄迁加。", "(邦云)这妇人是谁？(末唱)与妻儿远行劳困杀，太保也，可怜见俺背井离家。"]'),
('yuanqu-3995','吕洞宾桃柳升仙梦・南忆多娇','贾仲明','元','元曲','yuanqu','','[]','太保你谋害咱，则待杀。',58,'元曲/yuanqu.json','["太保你谋害咱，则待杀。", "金银宝贝尽纳下，且将性命都担饶罢。", "(邦云)有就放你回去。", "(旦唱)俺便行程，你是我重生父母报答。"]'),
('yuanqu-3996','吕洞宾桃柳升仙梦・北耍厮儿','贾仲明','元','元曲','yuanqu','','[]','你不要非真当假，大丈夫言出无差，轻言寡信休要耍。',51,'元曲/yuanqu.json','["你不要非真当假，大丈夫言出无差，轻言寡信休要耍。", "俺性命在天涯，泪似悬麻。", "(邦云)我务要杀你。", "(旦唱)。"]'),
('yuanqu-3997','吕洞宾桃柳升仙梦・南江神子','贾仲明','元','元曲','yuanqu','','[]','不由人心乱杀，眼睁睁夫妻分离下。',33,'元曲/yuanqu.json','["不由人心乱杀，眼睁睁夫妻分离下。", "远了家乡谁牵挂，谁想今朝命掩沙？。"]'),
('yuanqu-3998','吕洞宾桃柳升仙梦・北圣药王','贾仲明','元','元曲','yuanqu','','[]','则见他越怒发，难按纳，图财致命怎干罢？也是俺死限催，命运差。',196,'元曲/yuanqu.json','["则见他越怒发，难按纳，图财致命怎干罢？也是俺死限催，命运差。", "前生遇着这冤家。", "(邦云)杀！杀！(末唱)可怜我一命似飞花。", "(邦做杀科，云)休推睡里梦里，疾！(下)(末云)有杀人贼！(做醒科)(吕上云)柳春、陶氏，你二人省了么？(末同旦云)师父，弟子省了也。", "(吕云)你二人见了境头也？(末云)弟子见了也。", "(吕云)你二人跟我出家修行去，待一年半载，引你成仙了道，要你着意者。", "(末云)谢了师父。", "(唱)。"]'),
('yuanqu-3999','吕洞宾桃柳升仙梦・北尾声','贾仲明','元','元曲','yuanqu','','[]','从今后跟师父直至林泉下，拴住心猿意马。',110,'元曲/yuanqu.json','["从今后跟师父直至林泉下，拴住心猿意马。", "谢指教愿长生，紫府瑶池受用煞。", "(下)(吕云)此二人见了些境头，跟我修行去。", "待一年半载，着他成仙了道，未为晚矣。", "桃柳人间三十年，今将大道为他传。", "功成行满朝真去，一同参拜大罗仙。", "(下)。"]'),
('yuanqu-4000','吕洞宾桃柳升仙梦・北双调/新水令','贾仲明','元','元曲','yuanqu','','[]','三十年人事若痴愚，谢师父度脱俺省悟。',45,'元曲/yuanqu.json','["三十年人事若痴愚，谢师父度脱俺省悟。", "登山采药苗，近水结茅庐。", "则为那一梦华胥，跟师父赴仙路。"]'),
('yuanqu-4001','吕洞宾桃柳升仙梦・南昼锦堂','贾仲明','元','元曲','yuanqu','','[]','自古，道德非俗，修真养性，烧丹炼药工夫。',75,'元曲/yuanqu.json','["自古，道德非俗，修真养性，烧丹炼药工夫。", "利锁名缰，人我是非皆除。", "无虑，将宝贝金珠弃如土，若是有缘，终到青霄路。", "(合)寻真侣，今日向彩云深处，愿登仙府。"]'),
('yuanqu-4002','吕洞宾桃柳升仙梦・北甜水令','贾仲明','元','元曲','yuanqu','','[]','咱可便转过山冈，才离峻岭，崎岖绎路，(旦云)你看这里那桃柳，开的好艳冶也呵！(末唱)则见花柳锦模糊，你可便待向前来，折取一枝，休得辜负，(云)可怎生这里有此桃柳',93,'元曲/yuanqu.json','["咱可便转过山冈，才离峻岭，崎岖绎路，(旦云)你看这里那桃柳，开的好艳冶也呵！(末唱)则见花柳锦模糊，你可便待向前来，折取一枝，休得辜负，(云)可怎生这里有此桃柳？(唱)我可便参不透仙谋。"]'),
('yuanqu-4003','吕洞宾桃柳升仙梦・南四块金','贾仲明','元','元曲','yuanqu','','[]','桃红柳绿，则今日朱颜故。',64,'元曲/yuanqu.json','["桃红柳绿，则今日朱颜故。", "朝风暮雨，晓日迎烟雾。", "桃腮点嫩朱，柳眉愁未足。", "万绪千头，一点情舒。", "记得当初，也曾经恶雪霜风，受过无数苦。"]'),
('yuanqu-4004','吕洞宾桃柳升仙梦・北川拨棹','贾仲明','元','元曲','yuanqu','','[]','是谁人闹喧呼？唬的我魂魄无。',77,'元曲/yuanqu.json','["是谁人闹喧呼？唬的我魂魄无。", "我即便走出门户。", "(神云)那柳春，你见俺二人么？(末唱)见两个无徒。", "(神云)将金银宝贝来！(末唱)俺出家人有甚宝物？好教我便怒。"]'),
('yuanqu-4005','吕洞宾桃柳升仙梦・南川拨棹','贾仲明','元','元曲','yuanqu','','[]','因何故，有甚么宝贝金珠？你那里仗剑提刀，则是仙家伴侣。',70,'元曲/yuanqu.json','["因何故，有甚么宝贝金珠？你那里仗剑提刀，则是仙家伴侣。", "(神云)你好无礼也！(旦唱)我不曾敢冒渎。", "(神云)我就杀了你！(旦唱)休要将我性命图。"]'),
('yuanqu-4006','吕洞宾桃柳升仙梦・北七弟兄','贾仲明','元','元曲','yuanqu','','[]','这厮他恶语，畅好是狠毒，他一心待要图谋(云)要金银，你将的去！(神云)将来波！(末唱)将金银尽都收拾去。',70,'元曲/yuanqu.json','["这厮他恶语，畅好是狠毒，他一心待要图谋(云)要金银，你将的去！(神云)将来波！(末唱)将金银尽都收拾去。", "这一场全不用工夫，我和你两个前生注。"]'),
('yuanqu-4007','吕洞宾桃柳升仙梦・南锦衣香','贾仲明','元','元曲','yuanqu','','[]','他待要将俺诛，俺可也无门路。',129,'元曲/yuanqu.json','["他待要将俺诛，俺可也无门路。", "死难捱，合相遇。", "我可甚道门功行，祸福消除？眼睁睁死限在须臾。", "(神云)你二人受死！(旦唱)怎生得人来救我身躯？俺归泉世命已夫，磕头礼拜不放住。", "可怜见，可怜见，休教间阻。", "空望断，空望断，俺师父。", "(神云)我不饶你，务要杀了你！(末唱)。"]'),
('yuanqu-4008','吕洞宾桃柳升仙梦・北喜江南','贾仲明','元','元曲','yuanqu','','[]','师父也这其间朗吟飞过洞庭湖，(神做杀科，云)休推睡里梦里。',97,'元曲/yuanqu.json','["师父也这其间朗吟飞过洞庭湖，(神做杀科，云)休推睡里梦里。", "(末喊云)有杀人贼！(吕冲上云)你二人省了么？(末唱)；原来是吕纯阳又使这权术。", "见师父威严□□□寻俗，与俺便做主，愿师父明白指破这迷途。"]'),
('yuanqu-4009','中吕・喜春来','张弘范','元','元曲','yuanqu','','[]','金妆宝剑藏龙口，玉带红绒挂虎头，旌旗影里骤骅骝。',34,'元曲/yuanqu.json','["金妆宝剑藏龙口，玉带红绒挂虎头，旌旗影里骤骅骝。", "得志秋，喧满凤凰楼。"]'),
('yuanqu-4010','越调・天净沙梅梢月','张弘范','元','元曲','yuanqu','','[]','黄昏低映梅枝，照人两处相思，那的是愁肠断时。',67,'元曲/yuanqu.json','["黄昏低映梅枝，照人两处相思，那的是愁肠断时。", "弯弯何似？浑如宫样眉儿。", "西风落叶长安，夕阳老雁关山，今古别离最难。", "故人何处？玉箫明月空闲。"]'),
('yuanqu-4011','双调・殿前欢襄阳战','张弘范','元','元曲','yuanqu','','[]','鬼门关，朝中宰相五更寒。',53,'元曲/yuanqu.json','["鬼门关，朝中宰相五更寒。", "锦衣绣袄兵十万，枝剑摇环，定输赢此阵间。", "无辞惮，舍性命争功汗。", "将军战敌，宰相清闲。"]'),
('yuanqu-4012','翠红乡儿女两团圆・仙吕/赏花时','高茂卿','元','元曲','yuanqu','','[]','何须你簸扬我贪杯酒浸头，则你那闲言浯说念的春风树点头。',139,'元曲/yuanqu.json','["何须你簸扬我贪杯酒浸头，则你那闲言浯说念的春风树点头。", "(云)可也怪不的。", "(唱)从来这拙妇每他须巧舌头，(云)一家儿人家，被这等歹心的妇人每，都坏了也。", "(唱)他搜寻出这等分家私的由头，(云)我若早有个儿子，也不到得眼里看见如此。", "(唱)哎！这便是我没孩儿的那个下场头。", "(同二旦下)。"]'),
('yuanqu-4013','翠红乡儿女两团圆・仙吕/点绛唇','高茂卿','元','元曲','yuanqu','','[]','凛列风吹，雪花飘坠，弥天地。',26,'元曲/yuanqu.json','["凛列风吹，雪花飘坠，弥天地。", "不辨高低，似一片琼瑶砌。"]'),
('yuanqu-4014','翠红乡儿女两团圆・混江龙','高茂卿','元','元曲','yuanqu','','[]','莫不是春光明媚，既不沙可怎生有梨花乱落在这满空飞？这雪呵，供陶学士的茶灶，妆党太尉的筵席。',157,'元曲/yuanqu.json','["莫不是春光明媚，既不沙可怎生有梨花乱落在这满空飞？这雪呵，供陶学士的茶灶，妆党太尉的筵席。", "这雪呵，探梅客难寻三径去，便有那钓鱼翁也索披得一蓑归。", "幸际着太平时世，正遇着丰稔年岁。", "有新酿熟的白酒，旧腌下的肥鸡。", "自偎垆斟酌，没故友相知，则我放开怀连饮到数十巡。", "待要尽今生向这老瓦盆边醉，但守着竹篱茅舍，也不愿那画阁朱扉。"]'),
('yuanqu-4015','翠红乡儿女两团圆・油葫芦','高茂卿','元','元曲','yuanqu','','[]','我这里亲手高擎着这潋滟杯，李氏也我有句话苦劝你，则咱这家务事不许外人知，(带云)依着我的心呵，从今以后，(唱)则要您便欢欢喜喜相和会，不要你那般悲悲戚戚闲争气。',170,'元曲/yuanqu.json','["我这里亲手高擎着这潋滟杯，李氏也我有句话苦劝你，则咱这家务事不许外人知，(带云)依着我的心呵，从今以后，(唱)则要您便欢欢喜喜相和会，不要你那般悲悲戚戚闲争气。", "(春梅云)每日打骂我，怎么受的？(二旦云)你道波，我做甚么打你来？(正末云)你依着我呵，(唱)他要强与他牡强，你伏低且做低。", "你办着一片至诚的心，可自有个峥嵘日，你是必休折证是和非。"]'),
('yuanqu-4016','翠红乡儿女两团圆・天下乐','高茂卿','元','元曲','yuanqu','','[]','岂不闻道路上人也那口似碑？我如今便年也波纪，年纪可便近六十，虽然咱有家私，我这眼前无一个子息。',204,'元曲/yuanqu.json','["岂不闻道路上人也那口似碑？我如今便年也波纪，年纪可便近六十，虽然咱有家私，我这眼前无一个子息。", "(云)李氏也，我为你呵，多曾用心来。", "(唱)我背地里祷神祗，(带云)也不论是男是女，(唱)但得一个喂眼的，恰便似那心肝儿般知重你。", "(二旦云)这个老弟子孩儿无礼，心肝儿般知重他哩。", "(做唤门科，云)开门来，开门来。", "(正末做开门科，云)呀！二嫂来了也。", "(二旦云)老弟子，为这个泼贱奴胎说的我好也。", "我打这歪刺骨。", "(正末唱)。"]'),
('yuanqu-4017','翠红乡儿女两团圆・那吒令','高茂卿','元','元曲','yuanqu','','[]','你入门来便闹起，有甚的论黄数黑？街坊每都听知，谁敲牙波料嘴？这婆娘家便背悔也，忒瞒心昧己。',134,'元曲/yuanqu.json','["你入门来便闹起，有甚的论黄数黑？街坊每都听知，谁敲牙波料嘴？这婆娘家便背悔也，忒瞒心昧己。", "(二旦做打春梅科，云)我打这个歪刺骨。", "(正末云)二嫂休闪了手。", "(唱)火不登红了面皮，没揣的便揪住鬏髻，(二旦云)我打他有甚么事？(正末云)二嫂休闪了手。", "(唱)不歇手连打到有三十。"]'),
('yuanqu-4018','翠红乡儿女两团圆・鹊踏枝','高茂卿','元','元曲','yuanqu','','[]','哎！你一个歹东西，常好是不贤慧。',81,'元曲/yuanqu.json','["哎！你一个歹东西，常好是不贤慧。", "(二旦叫科，云)天也，韩弘道气杀我也。", "(正末唱)有甚事叫唤声疼，没来由出丑扬疾。", "可怎生全不依三从波四德，也是我不合将你来百纵千随。"]'),
('yuanqu-4019','翠红乡儿女两团圆・寄生草','高茂卿','元','元曲','yuanqu','','[]','你休恁般生嫉妒，休那般无智识。',89,'元曲/yuanqu.json','["你休恁般生嫉妒，休那般无智识。", "量这一个皮灯球犯下甚么滔大罪？哎，你一个鬼精灵会魔障这生人意，可知我这个酒糟头不识你这拖刀计。", "则恐怕李春梅夺了你那燕莺期，走将来黄桑棒打散了鸳鸯会。"]'),
('yuanqu-4020','翠红乡儿女两团圆・赚煞尾','高茂卿','元','元曲','yuanqu','','[]','罢、罢、罢，你今不听我这丈夫言，久以后必受俺那侄儿每的气。',145,'元曲/yuanqu.json','["罢、罢、罢，你今不听我这丈夫言，久以后必受俺那侄儿每的气。", "那厮每一个个贼心贼意，只待要吞占我的家私。", "你也须自做个见以，我言语尽是诚实。", "说着呵痛伤悲，怎不的蹙损的这愁眉？你也则是稳放着船到江心，那其间可便补漏迟。", "现如今有穿有吃，到后来无子无力，二嫂也，我只怕你得便宜翻做了一个落便宜。", "(下)。"]'),
('yuanqu-4021','翠红乡儿女两团圆・南吕/一枝花','高茂卿','元','元曲','yuanqu','','[]','这些时典卖了我些南亩田，耗散了中庭麦。',110,'元曲/yuanqu.json','["这些时典卖了我些南亩田，耗散了中庭麦。", "我将那少欠钱无心去索，婆婆也，这些时都只是盘缠了我自家的财。", "说着呵不由我感叹伤怀。", "我如今年纪老无接代，恨不的建一座望子台。", "我如今空盖着那郁沉沉大厦连甍，天那！几时能勾闹炒炒喧堂戏彩。"]'),
('yuanqu-4022','翠红乡儿女两团圆・梁州第七','高茂卿','元','元曲','yuanqu','','[]','谁着你便听信着徐卿的那二子，怎么来砍折了王氏三槐。',177,'元曲/yuanqu.json','["谁着你便听信着徐卿的那二子，怎么来砍折了王氏三槐。", "到如今岁寒然后知松柏。", "那两个蠢蠢之物，伴着伙泛泛之才。", "每日价贪图花酒，泼使钱财。", "倒将我劈面抢白，欺负咱软弱囊揣。", "都不到半年呵，早弄的家业个衰。", "则我那好言沿劝着他可更分毫不睬，他道我绝后波他是缘分上合该，这厮他纵心儿放乖。", "摸着的当了拿着的卖，使了自己少下人债。", "从今后依前若不改，婆婆也，是必着他休上我门来。"]'),
('yuanqu-4023','翠红乡儿女两团圆・牧羊关','高茂卿','元','元曲','yuanqu','','[]','这厮故意的将人吵，入门来便撒赖，他吃的醉沉沉放浪形骸。',171,'元曲/yuanqu.json','["这厮故意的将人吵，入门来便撒赖，他吃的醉沉沉放浪形骸。", "你看他行不动东倒西歪，哎哟！你觑他立不定天宽地窄。", "(福童云)叔叔，你无现钱，将那远年近岁欠下的文书，将来与俺两个索去。", "(王兽医做口扯文书科)(福童云)你慌做甚么？(正末唱)当日那举债钱是咱亲放，今日个要文书做您家财。", "至如我七十三八十四，(带云)哎！贼丑生每也，(唱)惯的您来千自由百自在。"]'),
('yuanqu-4024','翠红乡儿女两团圆・哭皇天','高茂卿','元','元曲','yuanqu','','[]','这厮那狠毒心如蜂虿，荒淫心忒分外。',152,'元曲/yuanqu.json','["这厮那狠毒心如蜂虿，荒淫心忒分外。", "堪恨这两个薄劣种，现世的不成才。", "只古里向咱家、咱家取索，也须知俺这三年五载，看看衰迈，还有甚精金响钞，暗暗藏埋。", "只被你两个泼无徒、泼无徒将俺来厮定害。", "没揣的大惊小怪，便待要生非作歹。", "(云)婆婆，家中有两箱柜文书，休开那锁钥，都与我抬将出来。", "(二旦着人抬出科)(正末唱)。"]'),
('yuanqu-4025','翠红乡儿女两团圆・乌夜啼','高茂卿','元','元曲','yuanqu','','[]','也不索将的去堂前晒，也不索检视的明白。',145,'元曲/yuanqu.json','["也不索将的去堂前晒，也不索检视的明白。", "(云)小的每，将些草来盖在柜止，再掌个灯来者。", "(唱)只一把火都烧做了纸灰来，(带云)烧了！烧了！(唱)请两个早离厅阶，自去安排。", "我待学刘员外仗义散家财，我待学庞居士放做了来生债。", "把我这宿世缘交天界，(带云)烧了！烧了！(唱)不强如焚钱烈楮，灭罪消灾？。"]'),
('yuanqu-4026','翠红乡儿女两团圆・贺新郎','高茂卿','元','元曲','yuanqu','','[]','我当年娶了个女裙钗，(王兽医云)他和婶子说的着么？(正末唱)为他每话不相投，因此上遣他在门外。',706,'元曲/yuanqu.json','["我当年娶了个女裙钗，(王兽医云)他和婶子说的着么？(正末唱)为他每话不相投，因此上遣他在门外。", "(王兽医云)他去了多少时节？(正末唱)经今早过了十三载，(王兽医云)这人敢还有么？(正末唱)他可便一去了呵，石沉大海。", "(王兽医云)叔叔，你打与我个模状儿。", "(正末唱)则他生的短矮也那蠢坌身材，(王兽医云)多大年纪也？(正末唱)他年庚有三十岁，(王兽医云)曾拐带了些甚么？(正未唱)止不过腹怀着半年胎。", "(王兽医云)曾着人打听来么？(正末唱)这其间知道和尚在也那钵盂在。", "(王兽医云)他小名儿唤做甚么？(正末唱)每日家问春梅无信息，(王兽医云)这人敢有哩。", "(正末唱)哎！他也恰便似赵杲送曾哀。", "(王兽医做打呵欠科)(正末云)哥，你莫不在那里见李春梅来？(王兽医云)没有见，我打了个呵欠。", "(正末云)将酒来与哥吃。", "(王兽医云)婶子，我要湿湿去。", "(二旦云)你看这厮波。", "(王兽医云)我出的这门来。", "(做溺尿科，云)姐夫，嗨！你好狠也，添添孩儿，有了主也。", "我过去说了，可是你绝户我绝户？(做过去见旦科，云)婶子，您侄儿湿湿湿了也。", "(二旦云)你看这厮波。", "(王兽医云)叔叔，我与婶子一个娃娃。", "(正末云)敢是醉了也。", "(王兽医云)我醉了，酒在肚里，事在心头。", "听的你把那十三年前的事说起来，我怕不与婶子一个娃娃？(正末云)婆婆，他说那十三年前的话，我有些耳背，你听者。", "(王兽医云)叔叔，我十三年前，去那四村上下看几个头口儿。", "那老的每便道：王兽医，天色晚了也，你休家去，兀那前面二十里巡铺上有鬼。", "我便道：我是人，可怎么倒怕鬼？到的二十里巡铺上，则听的那里面噎噎的啼哭。", "我道:咦！敢真个有鬼么？我拿起这捩鼻木来。", "喝了一声道：甚么人？他便道：我是个叫化的。"]'),
('yuanqu-4027','翠红乡儿女两团圆・骂玉郎','高茂卿','元','元曲','yuanqu','','[]','听说罢我便有九分来不快早十分也得快。',152,'元曲/yuanqu.json','["听说罢我便有九分来不快早十分也得快。", "(王兽医云)老的，你两口儿欢喜咱。", "(正末唱)不由我春满眼，喜盈腮，抵多少东风飘荡垂杨陌。", "(王兽医云)老的，你可有了后代儿孙也。", "(正末唱)一片心想后代，(王兽医云)我则是报答你仗义疏财的恩。", "(正末唱)三不知逢着贵客，(王兽医云)叔叔，也是天意。", "(正末唱)我两只手忙加额。"]'),
('yuanqu-4028','翠红乡儿女两团圆・感皇恩','高茂卿','元','元曲','yuanqu','','[]','天那，这的是苦尽甘来，(王兽医云)你命里有，则是有。',159,'元曲/yuanqu.json','["天那，这的是苦尽甘来，(王兽医云)你命里有，则是有。", "命里无，则是无。", "(正末唱)畅好是命也时哉。", "(王兽医云)若不是我说，你怎么知道？(正末唱)你个知心友泄天机，俺那青春子从天降，这个白头叟听天的那差。", "婆婆也，你把那鸡儿快宰，好酒频酾。", "(王兽医云)酒勾了，吃不的了也。", "(正末云)将酒来。", "(唱)与足下相庆贺，同喜悦，放愁怀。"]'),
('yuanqu-4029','翠红乡儿女两团圆・采茶歌','高茂卿','元','元曲','yuanqu','','[]','则我这个老奴才，若认了那小婴孩，(王兽医云)老的，一似枯树又逢春也。',78,'元曲/yuanqu.json','["则我这个老奴才，若认了那小婴孩，(王兽医云)老的，一似枯树又逢春也。", "(正末唱)哥也，我就似枯树上再花开。", "则道那一去了的孩儿在青霄外，谁承望洛阳的花酒一时来。"]'),
('yuanqu-4030','翠红乡儿女两团圆・黄钟尾','高茂卿','元','元曲','yuanqu','','[]','我则要你抱麟儿撞开孩子连环寨，婆婆也，我则要你引莺雏飞出韩侯那一座大会垓。',304,'元曲/yuanqu.json','["我则要你抱麟儿撞开孩子连环寨，婆婆也，我则要你引莺雏飞出韩侯那一座大会垓。", "想自家年老惫，忧念的我这须鬓白，则我这孤独的身也可哀。", "(云)哥，你和婆婆先去。", "(王兽医云)叔叔．我知道。", "(正末唱)我这里把这恩养钱我可也便百刂划，(带云)我虽无现在的，(唱)我这里或是典或是卖。", "尽着他言，由着他责。", "你则似那水也似流，风也似摆。", "使不着你糕也似团，婆婆也，我则要你谜也似猜。", "哥，不须我叮咛的向你行说一派，(带云)可到那里呵，(唱)用着你那巧言波令色。", "(二旦云)老的也，我知过了也。", "(正末唱)婆婆也，则要你知过而必改，(云)我到那里一头的见了我那孩儿，两只手抱的牢者。", "(唱)哎，你可便休道是拾得一个孩儿，落得价摔。", "(同下)。"]'),
('yuanqu-4031','翠红乡儿女两团圆・商调/集贤宾','高茂卿','元','元曲','yuanqu','','[]','则俺那小哥哥从幼儿便有志节。',109,'元曲/yuanqu.json','["则俺那小哥哥从幼儿便有志节。", "端的那顽劣处并无些。", "敢则是天生的聪俊，待改家门气象儿全别。", "写字儿写得来端方，对句儿比别人对的来真切。", "可久以后广寒宫里必将丹桂折，雷发声便动春蛰。", "则我看承他似堂上亲，把他来夸奖的就做了世间绝。"]'),
('yuanqu-4032','翠红乡儿女两团圆・金菊香','高茂卿','元','元曲','yuanqu','','[]','我则见他自推门跌自伤嗟，哎！哥也，你那般抹泪揉眵可是因甚也？我问道时无话说。',63,'元曲/yuanqu.json','["我则见他自推门跌自伤嗟，哎！哥也，你那般抹泪揉眵可是因甚也？我问道时无话说。", "哎！这桩事我敢猜者，哥也，多应是师父行吃了些亏折。"]'),
('yuanqu-4033','翠红乡儿女两团圆・梧叶儿','高茂卿','元','元曲','yuanqu','','[]','我听说罢着我醒如醉。',166,'元曲/yuanqu.json','["我听说罢着我醒如醉。", "可便唬的我来心似呆，(云)哥，你不知道王兽医是个不良的人？他问你父亲借具牛。", "你父亲不曾借与他，他记这些冤仇，阻隔您这父子的情也。", "(唱)我急慌里着些闲散活儿遮。", "(带云)王兽医，哎，(唱)他是个不睹事的乔男女，你便横枝儿待犯些口舌，那厮敢平地下锹撅，(带云)哎，哥也，则你休听他这酒魔的汉呵，(唱)一谜里便胡诌乱说。"]'),
('yuanqu-4034','翠红乡儿女两团圆・青哥儿','高茂卿','元','元曲','yuanqu','','[]','急的我两头儿无能、无能计设，俺姐姐虽不曾道怀耽、怀耽十月，哥也，那恩养你处何曾道倦怠了些？我常记的旧年时节，你身子儿薄怯，发着潮热，他将那锦绷儿绣藉，盖覆的个重',143,'元曲/yuanqu.json','["急的我两头儿无能、无能计设，俺姐姐虽不曾道怀耽、怀耽十月，哥也，那恩养你处何曾道倦怠了些？我常记的旧年时节，你身子儿薄怯，发着潮热，他将那锦绷儿绣藉，盖覆的个重叠。", "但有些儿焦忄敞，便解下摇车。", "乳哺的宁贴。", "恰得个休歇，俺姐姐真守到画眉窗外月儿斜，(带云)这也则为你呵。", "(唱)伴孤灯熬长夜。"]'),
('yuanqu-4035','翠红乡儿女两团圆・油葫芦','高茂卿','元','元曲','yuanqu','','[]','呀！可这壁厢便气杀他娘，(云)哥哥精细者，添添小哥来了也。',120,'元曲/yuanqu.json','["呀！可这壁厢便气杀他娘，(云)哥哥精细者，添添小哥来了也。", "姐姐精细者，添添小哥来了也。", "(唱)那壁厢冲倒他爷。", "哎哟！慌的我来战笃速这手儿可怎生抬揲？(带云)哥哥省烦恼！(唱)俺正是容易得来，你今日容易舍。", "也是咱前生的冤业，劝哥哥、姐姐莫痴呆。"]'),
('yuanqu-4036','翠红乡儿女两团圆・浪里来煞','高茂卿','元','元曲','yuanqu','','[]','这施恩不在年纪老，哎！扭打不必性儿劣。',87,'元曲/yuanqu.json','["这施恩不在年纪老，哎！扭打不必性儿劣。", "(带云)王兽医你好狠也呵。", "(唱)把俺这连枝树可怎么一时截？若是咱不烦恼则除心似铁。", "非干比便忒着那疼热，大刚咱这人生最苦是离别。", "(同下)。"]'),
('yuanqu-4037','翠红乡儿女两团圆・太平令','高茂卿','元','元曲','yuanqu','','[]','莫怪他泥中隐刺，(俞循礼云)俺是绝户的。',98,'元曲/yuanqu.json','["莫怪他泥中隐刺，(俞循礼云)俺是绝户的。", "(正末唱)他又不曾道节外生枝。", "也不索丁一卯二。", "(俞循礼云)都是王兽医来。", "(正末唱)且休问甚么张三波李四。", "咱两个老儿，到死时，令这个小嘶，我着他两下里丧拜祀。"]'),
('yuanqu-4038','翠红乡儿女两团圆・七弟兄','高茂卿','元','元曲','yuanqu','','[]','听说了姓儿，和这小字，不由我就不喜孜孜。',51,'元曲/yuanqu.json','["听说了姓儿，和这小字，不由我就不喜孜孜。", "这一场好事从天至。", "莫不是夏蝉高噪绿杨枝，险些儿西风了却黄花事。"]'),
('yuanqu-4039','翠红乡儿女两团圆・梅花酒','高茂卿','元','元曲','yuanqu','','[]','我觑了这女艳姿，如此般蠢坌身子，粗奘腰肢。',103,'元曲/yuanqu.json','["我觑了这女艳姿，如此般蠢坌身子，粗奘腰肢。", "却生的这般俊秀的孩儿。", "敢则是鸦窝里出凤凰。", "粪堆上产灵芝，这言语信有之。", "想天公果无私，将人心暗窥视。", "没揣的对付雄雌，酩子里接上连枝。", "(带云)春梅也，这一场呵，(唱)。"]'),
('yuanqu-4040','翠红乡儿女两团圆・收江南','高茂卿','元','元曲','yuanqu','','[]','呀！抵多少断肠人寄断肠词，今日个弄璋人说与弄璋的诗，都是那老天不绝俺宗支。',54,'元曲/yuanqu.json','["呀！抵多少断肠人寄断肠词，今日个弄璋人说与弄璋的诗，都是那老天不绝俺宗支。", "这一家儿恰似、恰似旱苗甘雨得来时。"]'),
('yuanqu-4041','翠红乡儿女两团圆・尾声','高茂卿','元','元曲','yuanqu','','[]','甫能认的孩儿至，又得个媳妇儿完成喜事。',43,'元曲/yuanqu.json','["甫能认的孩儿至，又得个媳妇儿完成喜事。", "尽着我瓦盆边饮白酒尽余生，画堂中戏斑衣快活个死。"]'),
('yuanqu-4042','包待制智赚生金阁・仙吕/赏花时','武汉臣','元','元曲','yuanqu','','[]','一来我应举京师赴选场，二来我为远去他乡躲祸殃，(卜儿云)孩儿也，俺子母每今日别去，不知何日相见？到得京师，你则着志者。',98,'元曲/yuanqu.json','["一来我应举京师赴选场，二来我为远去他乡躲祸殃，(卜儿云)孩儿也，俺子母每今日别去，不知何日相见？到得京师，你则着志者。", "(正末唱)就拜辞了老爹娘。", "非是您孩儿自夸得这自奖，我若是不富贵，可兀的不还乡。"]'),
('yuanqu-4043','包待制智赚生金阁・仙吕/点绛唇','武汉臣','元','元曲','yuanqu','','[]','则我这口内嗟吁，腹中忧虑。',64,'元曲/yuanqu.json','["则我这口内嗟吁，腹中忧虑。", "离家去，可又早一月多余，则我这白发添无数。", "(旦云儿)秀才，想古来也有未遇的人，这般受苦么？(正末唱)。"]'),
('yuanqu-4044','包待制智赚生金阁・混江龙','武汉臣','元','元曲','yuanqu','','[]','想前贤不遇，我便似阮嗣宗恸哭在穷途。',143,'元曲/yuanqu.json','["想前贤不遇，我便似阮嗣宗恸哭在穷途。", "早知道这般的担惊受恐，我可也图甚么衣紫拖朱？每日慵将书去习，逐朝常把药的那来扶。", "我这刚移足趾，强整身躯，滑七擦争些跌倒，战笃速恁艰虞。", "天也，我如今整三十，可着我半路里学那步？(旦云儿)秀才，你挣坐些着。", "(正末唱)但只见黑漫漫同云黯淡，白茫茫瑞雪模糊。"]'),
('yuanqu-4045','包待制智赚生金阁・天下乐','武汉臣','元','元曲','yuanqu','','[]','想刺股悬头去读书，则我这当也波初，自窨付，怕不的满胸中藏他万卷余。',66,'元曲/yuanqu.json','["想刺股悬头去读书，则我这当也波初，自窨付，怕不的满胸中藏他万卷余。", "又不曾上春官显姓名，又不曾向皇家请俸禄，哎，也干着了忍三冬受尽苦。"]'),
('yuanqu-4046','包待制智赚生金阁・金盏儿','武汉臣','元','元曲','yuanqu','','[]','我则见他人马闹喧呼，这人物不寻俗。',71,'元曲/yuanqu.json','["我则见他人马闹喧呼，这人物不寻俗。", "一群价飞鹰走犬相随逐，都是些貂裘暖帽锦衣服。", "虽不见门排十二戟，户列入椒图，你觑那金牌上悬铜虎，玉带上挂银鱼。"]'),
('yuanqu-4047','包待制智赚生金阁・醉扶归','武汉臣','元','元曲','yuanqu','','[]','小生呵，家住在河中府。',154,'元曲/yuanqu.json','["小生呵，家住在河中府。", "(衙内云)曾学甚么武艺来？(正末唱)幼年间读几行圣贤书。", "(衙内云)这等，你可怎么不做官？(正末唱)则为我运拙时乖天不与，(衙内云)可知则是一个穷秀才。", "(正末唱)甘分守穷活路。", "(衙内云)你家里有甚么人？(正末唱)拜辞了年高的父母，(衙内云)你如今往那里去？(正末云)我一径的取应往梁园去。"]'),
('yuanqu-4048','包待制智赚生金阁・金盏儿','武汉臣','元','元曲','yuanqu','','[]','听小生说从初，(衙内云)可也端的少有。',194,'元曲/yuanqu.json','["听小生说从初，(衙内云)可也端的少有。", "(正末唱)这宝贝世间无，(衙内云)你可那里得来？(正末唱)俺家里祖传三辈牢收取。", "(衙内云)你可要多少钱钞？(正末唱)我也不求厚赂，但遂意，便沽诸。", "(衙内云)我与你些绫罗段匹换的么？(正末唱)也不要绫罗段匹，(衙内云)与你些宝贝金珠可好？(正末唱)也不要宝贝共金珠。", "(衙内云)你都不要，可要些甚么？(正末唱)小生只博个小前程来帝里，便也好将名分入乡闾。"]'),
('yuanqu-4049','包待制智赚生金阁・赚煞','武汉臣','元','元曲','yuanqu','','[]','罢、罢、罢，怎干休，难分诉，世做的冯河暴虎，赤紧的先要了我这希奇无价物，又生出百计亏图。',126,'元曲/yuanqu.json','["罢、罢、罢，怎干休，难分诉，世做的冯河暴虎，赤紧的先要了我这希奇无价物，又生出百计亏图。", "哎，你个泼无徒，胆大心粗。", "俺夫妻每负屈衔冤谁做主？你强夺了花枝媳妇，又将咱性命屠毒，(带云)哎，早知今日，我不带的浑家出来也罢。", "(唱)方知道\"美女累其夫\"。", "(下)。"]'),
('yuanqu-4050','包待制智赚生金阁・紫花儿序','武汉臣','元','元曲','yuanqu','','[]','早辰间放开仓库，晌午里绰扫了花园，末傍晚我又索执料厨房。',92,'元曲/yuanqu.json','["早辰间放开仓库，晌午里绰扫了花园，末傍晚我又索执料厨房。", "小丫鬟忙来呼唤，道衙内共我商量。", "岂敢行唐？大走向庭前去问当。", "(正旦做见衙内科)(唱)哥哥，你有何明降？对老身至尾从头，说短论长。"]'),
('yuanqu-4051','包待制智赚生金阁・小桃红','武汉臣','元','元曲','yuanqu','','[]','老身非敢自夸强，我不比那蒯通无名望。',143,'元曲/yuanqu.json','["老身非敢自夸强，我不比那蒯通无名望。", "(衙内云)我礼拜磕头，央及你波。", "(衙内做拜科)(正旦唱)呀、呀、呀，何须的礼拜磕头把咱央？(衙内云)好奶奶，没奈何，好生劝他一劝。", "(正旦唱)直恁般痛着忙，就待要安排共宿芙容帐。", "凭着我甜话儿厮搪，更将些美情儿相向。", "哥哥也，你稳情取金殿锁鸳鸯。", "(同下)。"]'),
('yuanqu-4052','包待制智赚生金阁・凭栏人','武汉臣','元','元曲','yuanqu','','[]','则这女聘男婚礼正当。',141,'元曲/yuanqu.json','["则这女聘男婚礼正当。", "你两下和谐可着人赞扬，哎，你个女艳妆，你心中可怎不思想？(旦儿云)嬷嬷，你怎知道？我那里是大财大礼娶的？我本是郭成的浑家，有庞衙内强要了我生金阁儿，又逼我为妻，将俺丈夫锁在马房里。", "嬷嬷？你可知道我这等冤枉也！(正旦云)你若不说，我怎生得知？难道有这等事？(唱)。"]'),
('yuanqu-4053','包待制智赚生金阁・鬼三台','武汉臣','元','元曲','yuanqu','','[]','听的他言分朗，唬的我魂飘荡。',170,'元曲/yuanqu.json','["听的他言分朗，唬的我魂飘荡。", "姐姐也，你怎生则撞入天罗地网？俺那厮驴狗儿一片家狠心肠，有谁人好来阻当？(旦儿云)嬷嬷，我今日不曾看见丈夫，多敢杀坏了。", "兀的不痛杀我也。", "(正旦唱)你道他昨来个那埚儿里杀坏了范杞梁，今日个这埚儿里没乱杀你女孟姜。", "(旦儿云)嬷嬷，我待要寻一个大大的衙门，告他去哩！(正旦唱)你侍要叫屈声冤，姐姐也，谁敢便收词接状？。"]'),
('yuanqu-4054','包待制智赚生金阁・寨儿令','武汉臣','元','元曲','yuanqu','','[]','我见他痛感伤，泪汪汪，(旦儿云)当初只为我生的风流，长的可喜，将我男儿陷害了性命，挝了我这面皮罢。',118,'元曲/yuanqu.json','["我见他痛感伤，泪汪汪，(旦儿云)当初只为我生的风流，长的可喜，将我男儿陷害了性命，挝了我这面皮罢。", "(正旦云)哎哟，可惜了也。", "(唱)水晶般指甲儿挝破面上。", "(衙内同随从做听科)(正旦唱)俺那厮少不的落马身足庄。", "不久沦亡，他可便遭贼盗值重丧。"]'),
('yuanqu-4055','包待制智赚生金阁・幺篇','武汉臣','元','元曲','yuanqu','','[]','多不到半月时光。',42,'元曲/yuanqu.json','["多不到半月时光。", "餐刀刃亲赴云阳，高杆首吊脊梁，木驴上碎分张，浑身的害么娘碗大血疔疮。"]'),
('yuanqu-4056','包待制智赚生金阁・金蕉叶','武汉臣','元','元曲','yuanqu','','[]','是谁人村声泼嗓？他壁听在门儿外厢。',66,'元曲/yuanqu.json','["是谁人村声泼嗓？他壁听在门儿外厢。", "(旦儿做惊科，云)嬷嬷，窗儿外有人咳嗽。", "(正旦唱)姐姐也，你且休慌心劳意攘，我可便自把那言词说上。"]'),
('yuanqu-4057','包待制智赚生金阁・调笑令','武汉臣','元','元曲','yuanqu','','[]','息怒波宰相，听老身说行藏。',140,'元曲/yuanqu.json','["息怒波宰相，听老身说行藏。", "(衙内云)你还说甚的？可敢再骂我么？(正旦云)哥哥，我不曾说甚来？(唱)我道是楚襄王寄语巫山窈窕娘，也不须遮遮掩掩妆模样，早共晚准备下雨席云床。", "(衙内云)你道不骂我，恰才我都听的了也。", "(正旦唱)我道您哥哥也，在城中第一家财帛广，还有那鸦飞不过的田地池塘。"]'),
('yuanqu-4058','包待制智赚生金阁・梁州第七','武汉臣','元','元曲','yuanqu','','[]','我也则为那万般愁常萦心上，两条恨不去眉梢，急回身又遇着新春到。',184,'元曲/yuanqu.json','["我也则为那万般愁常萦心上，两条恨不去眉梢，急回身又遇着新春到。", "我只见寒梅晚谢，冻雪初消。", "傍几家儿村鸡哑哑，隔半程儿野犬口牢口牢。", "妆点来则恁的景物萧条，可不道有丹青也便巧笔难描。", "我、我、我，看了些青渗渗峻岭层峦，是、是、是，行了些黄穰穰沙堤得这古道，呀、呀、呀，兀良，早过了些碧澄澄野水横桥。", "归来路杳，袅丝鞭羡杀投林鸟。", "薄暮也，在荒郊，怎当这疲马西风雪正飘，说不尽寂寥。"]'),
('yuanqu-4059','包待制智赚生金阁・贺新郎','武汉臣','元','元曲','yuanqu','','[]','他那里擎杯举酒对天浇，现如今五谷丰登，万民安乐，卖弄池田蚕十倍收成了。',98,'元曲/yuanqu.json','["他那里擎杯举酒对天浇，现如今五谷丰登，万民安乐，卖弄池田蚕十倍收成了。", "说不尽庄家，庄家这好，还待要薄税轻徭。", "他道官长每如卓鲁，令史每压萧曹，高眠莫被闲愁搅。", "似这等人心无压足厌则怕天也填不的许多凹。"]'),
('yuanqu-4060','包待制智赚生金阁・牧羊关','武汉臣','元','元曲','yuanqu','','[]','他那里才言罢，唬的我魂暗消。',94,'元曲/yuanqu.json','["他那里才言罢，唬的我魂暗消。", "离城中则半载其高，可怎么白日神嚎，到黄昏鬼闹。", "我半生多正直，怎见这蹊跷？只今的离村疃犹然早，(云)张千，将马来。", "(张千云)理会的。", "(正末唱)我和你到皇都赴晚朝。"]'),
('yuanqu-4061','包待制智赚生金阁・哭皇天','武汉臣','元','元曲','yuanqu','','[]','则你那"催动坑"刚才道，可怎生这公事便妆幺？则你那口是祸之苗，(娄青做打脸科，云)你怎么多嘴？(正末唱)舌是斩身刀。',272,'元曲/yuanqu.json','["则你那\"催动坑\"刚才道，可怎生这公事便妆幺？则你那口是祸之苗，(娄青做打脸科，云)你怎么多嘴？(正末唱)舌是斩身刀。", "(带云)娄青，(唱)你与我去城隍根前祝祷，(娄青云)爷着孩儿祝祷甚的？(正末唱)你说与那衔冤的业鬼，屈死的冤魂，你着他今宵插状，此夜呈词。", "你道这包龙图专在南衙里，南衙里等待着，(娄青云)您孩儿知道了，便勾去。", "(正末云)娄青你转来，天色还早哩。", "(娄青云)这等多早晚去？(正末唱)直等的金乌向山坠，银蟾出海角。", "(娄青云)您孩儿便依着爷的言语，对城隍神道祝祷了。", "他两个耳朵是泥塑的，怕不听见？(正末云)娄青，我与你一道牒文去。", "(唱)。"]'),
('yuanqu-4062','包待制智赚生金阁・黄钟尾','武汉臣','元','元曲','yuanqu','','[]','我若是不应心，今夜便辞了宣诏，(娄青云)爷，应的口么？(正末唱)我若是不应口，今番不姓包。',157,'元曲/yuanqu.json','["我若是不应心，今夜便辞了宣诏，(娄青云)爷，应的口么？(正末唱)我若是不应口，今番不姓包。", "(娄青云)您孩儿多早晚时候去？(正末云)天色早哩。", "(唱)直等的初更残二鼓交，把冤魂摄来到。", "审个真实，问个下落，杀人贼便拿捉，赴云阳向市曹，将那厮高杆上挑，把脊筋来吊。", "我着那横亡人便得生天，众百姓把咱来可兀的称赞到老。", "(下)。"]'),
('yuanqu-4063','包待制智赚生金阁・双调/新水令','武汉臣','元','元曲','yuanqu','','[]','透襟怀一阵冷风吹，则他这闭长空暮云都退。',52,'元曲/yuanqu.json','["透襟怀一阵冷风吹，则他这闭长空暮云都退。", "显出那碧澄澄天气爽，明皎皎月光辉，厮和着灯焰相窥，照耀的似白日。"]'),
('yuanqu-4064','包待制智赚生金阁・沉醉东风','武汉臣','元','元曲','yuanqu','','[]','则我那开封府门神户尉，你与我快传示莫得延迟。',95,'元曲/yuanqu.json','["则我那开封府门神户尉，你与我快传示莫得延迟。", "你教他放过那屈死的魂，衔冤的鬼，只当住邪魔恶祟。", "(娄青云)烧了这纸钱，你看好冷风也。", "(正末唱)我则见黯黯的愁云惨雾迷，嗨，可早变的来天昏也那地黑。"]'),
('yuanqu-4065','包待制智赚生金阁・庆东原','武汉臣','元','元曲','yuanqu','','[]','纸钱向身边挂，人头向手内提，向前来紧靠着灯前跪。',99,'元曲/yuanqu.json','["纸钱向身边挂，人头向手内提，向前来紧靠着灯前跪。", "我这里叮咛的问你：你家住在那里？(魂子云)孩儿每河中府人氏。", "(正末唱)姓甚名准？(魂子云)姓郭名成。", "(正末唱)你可也做财主、做经商？为黎庶、为官吏？。"]'),
('yuanqu-4066','包待制智赚生金阁・雁儿落','武汉臣','元','元曲','yuanqu','','[]','昨宵个牒城隍将怨鬼提，到今日放南衙果有冤词递。',45,'元曲/yuanqu.json','["昨宵个牒城隍将怨鬼提，到今日放南衙果有冤词递。", "元来是庞衙内使尽他狼虎威，生拆散你这鸳鸯对。"]'),
('yuanqu-4067','包待制智赚生金阁・得胜令','武汉臣','元','元曲','yuanqu','','[]','呀，他敢将萧何律做成衣，将罪犯满身披。',71,'元曲/yuanqu.json','["呀，他敢将萧何律做成衣，将罪犯满身披。", "谁许他谋了财，又要谋人命？准许他夺人妻逼做妻？直恁的无知。", "那嬷嬷担何罪？死的个堪悲。", "我与你勾他来问到底。"]'),
('yuanqu-4068','包待制智赚生金阁・沽美酒','武汉臣','元','元曲','yuanqu','','[]','略使些小见识，智赚出杀人贼。',78,'元曲/yuanqu.json','["略使些小见识，智赚出杀人贼。", "这场事天教还报你，我可便有言语敢题，并不要你还席。", "(衙内云)老宰辅不要我还席，好快活也。", "咱则一家一计，吃个尽兴方归。", "(正末唱)。"]'),
('yuanqu-4069','好酒赵元遇上皇・仙吕/点绛唇','高文秀','元','元曲','yuanqu','','[]','东倒西歪，后合前仰，离席上。',27,'元曲/yuanqu.json','["东倒西歪，后合前仰，离席上。", "这酒兴颠狂，醉魂儿望家往。"]'),
('yuanqu-4070','好酒赵元遇上皇・混江龙','高文秀','元','元曲','yuanqu','','[]','我这里猛然观望，风吹青旆唤高阳。',95,'元曲/yuanqu.json','["我这里猛然观望，风吹青旆唤高阳。", "吃了这发醅醇糯，胜如那玉液琼浆。", "喜的是两袖清风和月偃，一壶春色透瓶香。", "花前饮酒，月下掀髯；蓬头垢面，鼓腹讴歌；茅舍中酒瓮边刺登哩登唱。", "三杯肚里，由你万古传扬。"]'),
('yuanqu-4071','好酒赵元遇上皇・油葫芦','高文秀','元','元曲','yuanqu','','[]','你道我恋酒贪杯厮定当；（孛老云）你这等不成半器，我打这个糟弟子孩儿（正末唱）你畅好村莽撞。',379,'元曲/yuanqu.json','["你道我恋酒贪杯厮定当；（孛老云）你这等不成半器，我打这个糟弟子孩儿（正末唱）你畅好村莽撞。", "（卜儿云）老的，打这弟子孩儿。", "（孛老云）婆婆，我知道，我打他怕甚么！（正末唱）可知道你名儿唤做一窝狼。", "（擦旦云）村弟子孩人，每日家酒里眠，酒里卧，不着家里，撇的我冷冷清清。", "你吃这酒；有何好处？（正末唱）你不见桃花未曾来腮上，可又早阑珊了竹叶尊前唱。", "（搽旦云）父亲，和这等东西，有甚么好话？讲出甚么理来？狗口里吐不出象牙。", "向前打这贪酒不干营生糟丑生贼弟子孩儿。", "（孛老云）孩儿你说的是，我打这弟子孩儿。", "（打科）（正末唱）嗤嗤把头发揪，（搽旦云）父亲拳撞脚踢，与他个烂羊头。", "（孛老云）我踢这不成半器的畜生。", "（正末唱）连连的使脚撞，（李老云）我耳根拳打这狗弟子孩儿。", "（正末唱）耳根上一迷里直拳抢，（搽旦云）你穿的这尸皮，不是我做的？我扯碎你的。", "（正末唱）他恶狠狠都扯破我衣裳。"]'),
('yuanqu-4072','好酒赵元遇上皇・那吒令','高文秀','元','元曲','yuanqu','','[]','前日是瞎王三上梁，（孛老云）昨日在那里吃酒来？（正末唱）昨日是村李胡赛羊，（孛老云）今日又醉了，可是那里吃酒来？（正末唱）今日是酒刘洪贵降。',144,'元曲/yuanqu.json','["前日是瞎王三上梁，（孛老云）昨日在那里吃酒来？（正末唱）昨日是村李胡赛羊，（孛老云）今日又醉了，可是那里吃酒来？（正末唱）今日是酒刘洪贵降。", "（搽旦云）好朋友都是伙不上台盘的狗油东西。", "（李老云）你这厮，每日则吃酒，不做生理，怎么是好？（正末唱）我本待不出来，他每都来相访，怎当他相领相将？。"]'),
('yuanqu-4073','好酒赵元遇上皇・鹊踏枝','高文秀','元','元曲','yuanqu','','[]','有酒后聚的亲房，有酒后会的贤良。',115,'元曲/yuanqu.json','["有酒后聚的亲房，有酒后会的贤良。", "（搽旦云）呸！你不识羞。", "每日伴着些狐朋狗党，那个是好的？为这酒有甚么好处？（正末唱）岂不闻俗语常言；酒解愁肠。", "（卜儿云）你吃了酒，又惹是非，累及俺一家儿。", "（正未唱）我有酒后宽洪海量，没酒时腹热肠慌。"]'),
('yuanqu-4074','好酒赵元遇上皇・寄生草','高文秀','元','元曲','yuanqu','','[]','者末为经纪，做货郎。',111,'元曲/yuanqu.json','["者末为经纪，做货郎。", "使牛做豆将田耩，搽灰抹粉学搬唱，剃头削发为和尚。", "（搽旦云）我不和你撒赖撒痴的，断了酒者！（正末唱）教我断消愁解闷瓮头香，（搽旦云）断了者，断了者！（正未云）断不的，断不的！（唱）情愿去云阳闹市伸着脖项。"]'),
('yuanqu-4075','好酒赵元遇上皇・醉中天','高文秀','元','元曲','yuanqu','','[]','春暖群芳放，（李老云）夏里断呵？（正末云）夏里断呵，（唱）夏暑芰荷香。',149,'元曲/yuanqu.json','["春暖群芳放，（李老云）夏里断呵？（正末云）夏里断呵，（唱）夏暑芰荷香。", "（孛老云）秋里断呵？（正末云）秋里断呵，（唱）金井梧桐败叶黄，(孛老云)冬里断呵？（正末云）冬里断呵，(唱)怎当那瑞雪飞头上？（云）天有不测风雨，人有旦夕祸福。", "（唱）人生死则在一时半晌，你教我断了金波绿酿，却不等闲的虚度时光？。"]'),
('yuanqu-4076','好酒赵元遇上皇・金盏儿','高文秀','元','元曲','yuanqu','','[]','你教我住村舍伴芒郎，养皮袋住村坊。',102,'元曲/yuanqu.json','["你教我住村舍伴芒郎，养皮袋住村坊。", "每日价风吹日炙将田耩，和那沙三赵四受风霜。", "怎能够百年浑是醉，三万六千场。", "（云）父亲，有两件断不的这酒。", "（孛老云）可是那两件？（正末唱）常言道野花攒地出，我则怕村酒透瓶香。"]'),
('yuanqu-4077','好酒赵元遇上皇・游四门','高文秀','元','元曲','yuanqu','','[]','他待将好花分付与富家郎，夫妇两分张。',41,'元曲/yuanqu.json','["他待将好花分付与富家郎，夫妇两分张。", "目下申文书难回向，眼见的一身亡，他却待配鸾凰。"]'),
('yuanqu-4078','好酒赵元遇上皇・柳叶儿','高文秀','元','元曲','yuanqu','','[]','赤紧的司公厮向，走将来雪上加霜。',48,'元曲/yuanqu.json','["赤紧的司公厮向，走将来雪上加霜。", "唬的我悠悠的魂飘荡，何处呈词状？若写呵免灾殃，不写呵更待何妨！。"]'),
('yuanqu-4079','好酒赵元遇上皇・赏花时','高文秀','元','元曲','yuanqu','','[]','则为一貌非俗离故乡，二四的司公能主张。',43,'元曲/yuanqu.json','["则为一貌非俗离故乡，二四的司公能主张。", "则他三个人狠心肠，做夫妻四年向上，五十次告官房。"]'),
('yuanqu-4080','好酒赵元遇上皇・幺篇','高文秀','元','元曲','yuanqu','','[]','六合内经你不良，把我七代先灵信口伤。',42,'元曲/yuanqu.json','["六合内经你不良，把我七代先灵信口伤。", "八下胡论告恶商量，做夫妻久想，莫要十指望便身亡。"]'),
('yuanqu-4081','好酒赵元遇上皇・梁州第七','高文秀','元','元曲','yuanqu','','[]','假若韩退之蓝关外不前骏马，孟浩然灞陵桥不肯骑驴。',141,'元曲/yuanqu.json','["假若韩退之蓝关外不前骏马，孟浩然灞陵桥不肯骑驴。", "冻的我战兢兢手脚难停住。", "更那堪天寒日短，旷野消疏。", "关山寂寞，风雪交杂。", "浑身上单夹衣服，舞东风乱糁珍珠。", "抬起头似出窟顽蛇，缩着肩似水淹老鼠，躬着腰人样虾蛆。", "几时到帝都？刮天刮地狂风鼓，谁曾受这番苦？见三疋金鞍拴在老桑树，多敢是国戚皇族。"]'),
('yuanqu-4082','好酒赵元遇上皇・牧羊关','高文秀','元','元曲','yuanqu','','[]','见酒后忙参拜，饮酒后再取覆，共这酒故人今日完聚。',73,'元曲/yuanqu.json','["见酒后忙参拜，饮酒后再取覆，共这酒故人今日完聚。", "酒呵，则到永不相逢，不想今番重聚。", "为酒上遭风雪，为酒上践程途。", "这酒浸头和你重相遇，酒爹爹安乐否？。"]'),
('yuanqu-4083','好酒赵元遇上皇・隔尾','高文秀','元','元曲','yuanqu','','[]','小人则是个随驴把马乔男女，你须是说古论文士大夫。',220,'元曲/yuanqu.json','["小人则是个随驴把马乔男女，你须是说古论文士大夫。", "这六点儿运人不曾把人做。", "我虽是愚浊的匹夫，不会讲先王礼数，（驾云）君子饮过这一杯酒者。", "（正末唱）我这里氵虢氵虢的咽喉中咽下去。", "（驾云）那壁哥哥，你慢慢的饮几杯，俺三人酒够了，俺先回去来。", "（做起身科）（酒保云）这三个秀才好无礼也，你吃了我酒，钱也不还，你往那里去？（驾云）俺身边无钱，改日还你。", "（酒保云）你吃了酒不还钱，我不放你去。", "打这三个无知的人！（做厮打科）（正末听科）是好奇怪也！（唱）。"]'),
('yuanqu-4084','好酒赵元遇上皇・采茶歌','高文秀','元','元曲','yuanqu','','[]','一个扯着衣服，一个更醉模糊，早难道满身花影倩人扶？三位儒人休恐惧，我替还酒债出青蚨。',42,'元曲/yuanqu.json','["一个扯着衣服，一个更醉模糊，早难道满身花影倩人扶？三位儒人休恐惧，我替还酒债出青蚨。"]'),
('yuanqu-4085','好酒赵元遇上皇・红芍药','高文秀','元','元曲','yuanqu','','[]','丈人丈母狠心毒，更那堪司公府尹糊涂。',110,'元曲/yuanqu.json','["丈人丈母狠心毒，更那堪司公府尹糊涂。", "（驾云）你浑家怎不贤惠？（正末唱）果然这美女累其夫，他可待似水如鱼，好模样，歹做出，不睹事，要休书。", "（驾云）你那东京府尹，怎敢强娶你浑家？（正末唱）他倚官强拆散俺妻夫，真乃是牛马襟裾。"]'),
('yuanqu-4086','好酒赵元遇上皇・菩萨梁州','高文秀','元','元曲','yuanqu','','[]','我须是鳏寡孤独，对谁人分诉，衔冤负屈？（驾云）你这等啼哭也无用也。',289,'元曲/yuanqu.json','["我须是鳏寡孤独，对谁人分诉，衔冤负屈？（驾云）你这等啼哭也无用也。", "（正末唱）因此上气填胸雨泪如珠。", "（驾云）赵元，我救你这一命，你意下如何？（正末云）哥哥，你怎生救我？（驾云）你放心，我与上京丞相赵光普一面之交。", "我欲待写书去，途中无纸。", "楚昭辅，你袖中将的霜毫笔来，你扳着赵元臂膊，石守信扶着兄弟，我在你臂膊上写两行字，画一个押字。", "若赵丞相见了时，你必然不死也。", "（楚、石二人扶正末科）（正末唱）一个举霜毫，一个扳臂膊，一个把咱扶着，道两行字便是我生天疏。", "（楚云）这两行字书、若到上京见了赵丞相，你必不死也。", "（正末唱）却教我无事还乡故，这好事要人做。", "不想二百长钱买了命处，胜似纸天书。"]'),
('yuanqu-4087','好酒赵元遇上皇・尾声','高文秀','元','元曲','yuanqu','','[]','谁想今番横死身躯得恩顾，遥指云中雁寄书，两只脚不停住。',77,'元曲/yuanqu.json','["谁想今番横死身躯得恩顾，遥指云中雁寄书，两只脚不停住。", "这忧愁，这凄楚，这烦恼，这思虑，怎声扬，忒负屈。", "赵光普你执掌权枢，怎知俺冒风雪射粮军于受苦？（下）。"]'),
('yuanqu-4088','好酒赵元遇上皇・中吕/粉蝶儿','高文秀','元','元曲','yuanqu','','[]','六出花飞，碧大也乐云不退，抱双肩紧把头低。',51,'元曲/yuanqu.json','["六出花飞，碧大也乐云不退，抱双肩紧把头低。", "醉魂消，洒才醒．四肢无力。", "眼见得命掩泉泥，这场灾怎生冲避？。"]'),
('yuanqu-4089','好酒赵元遇上皇・醉春风','高文秀','元','元曲','yuanqu','','[]','送了我也竹叶瓮头春，花枝心爱妻。',54,'元曲/yuanqu.json','["送了我也竹叶瓮头春，花枝心爱妻。", "则为恋香醪寻着永别离，到今日悔，悔，悔！也是我前世前缘，自作自受，怨天怨地。"]'),
('yuanqu-4090','好酒赵元遇上皇・迎仙客','高文秀','元','元曲','yuanqu','','[]','狼虎股排着从人，雁翅般列着公吏。',58,'元曲/yuanqu.json','["狼虎股排着从人，雁翅般列着公吏。", "这无常略来人不知，我又不会脱身术，又不会插翅飞。", "止不过泪若扒推，这的是自寻的无头罪。"]'),
('yuanqu-4091','好酒赵元遇上皇・上小楼','高文秀','元','元曲','yuanqu','','[]','有你哥哥信息，小人阶前分细。',87,'元曲/yuanqu.json','["有你哥哥信息，小人阶前分细。", "怏怏疾疾，端端的的，诉说真实。", "（光普云）你说我听，若说的是呵，万事罢论；说的不是呵，必不轻恕！（正末唱）若赵元，说的来，差之毫厘，情愿便命归泉世。"]'),
('yuanqu-4092','好酒赵元遇上皇・幺篇','高文秀','元','元曲','yuanqu','','[]','一行三个人，殷勤劝一杯。',67,'元曲/yuanqu.json','["一行三个人，殷勤劝一杯。", "不承望少下酒钱，店主人家唱叫扬疾。", "（光普云）你可怎么劝来？（正末唱）我替还了二百钱，别无思议，出此上认为兄弟。"]'),
('yuanqu-4093','好酒赵元遇上皇・十二月','高文秀','元','元曲','yuanqu','','[]','纳我在交椅上坐地，拿着我手脚身躯。',45,'元曲/yuanqu.json','["纳我在交椅上坐地，拿着我手脚身躯。", "地铺着绣褥，香喷着金猊。", "唤大夫是甚脉息？则我这病眼难医。"]'),
('yuanqu-4094','好酒赵元遇上皇・尧民歌','高文秀','元','元曲','yuanqu','','[]','几曾见悲田院土地拜钟馗，判官当厅问牙椎。',142,'元曲/yuanqu.json','["几曾见悲田院土地拜钟馗，判官当厅问牙椎。", "神针法灸那般疾，恰便似蓝采和舞不迭看花回。", "冷笑微微，吾皇敕赐的，判断开封位。", "（光普云）御弟你听者：圣人命加你为东京府尹，即今走马到任，一壁厢便造文书。", "（正末云）教我做东京府尹？那衙门里有酒么？（光普云）作则要吃酒，则今日便索长行也。", "（正末唱）。"]'),
('yuanqu-4095','好酒赵元遇上皇・耍孩儿','高文秀','元','元曲','yuanqu','','[]','不会做官看取傍州例，五刑文书整理。',69,'元曲/yuanqu.json','["不会做官看取傍州例，五刑文书整理。", "便萧曹律令不曾习，有档案分令交支持。", "没酒的休入衙门里，除睡人间总不知。", "无萦系，问甚从人司吏，吃了后回席。"]'),
('yuanqu-4096','好酒赵元遇上皇・二煞','高文秀','元','元曲','yuanqu','','[]','饮酒如李太白，糊突似包待制。',67,'元曲/yuanqu.json','["饮酒如李太白，糊突似包待制。", "唤我做没底瓶，普天下人皆识。", "青云有路终须到，好酒无名誓不归。", "每日价醺醺醉，管甚么三推六问，不如那百盏充席。"]'),
('yuanqu-4097','好酒赵元遇上皇・尾声','高文秀','元','元曲','yuanqu','','[]','问甚么秋泉竹叶青，九酝荷叶杯。',140,'元曲/yuanqu.json','["问甚么秋泉竹叶青，九酝荷叶杯。", "不拣你与我沧浪水，也强似忍风雪饥寒半路里。", "(下)（光普云）此人去了也。", "谁想此人酒务中，遇见上皇，就臂膊上写了花押，认为兄弟，加为东京府尹，走马到任。", "圣人若回家，别有加官。", "今日无甚事，左右将马来，且回私宅中去来。", "圣人酒店逢知己，加做东京府尹官。", "（下）。"]'),
('yuanqu-4098','好酒赵元遇上皇・乔牌儿','高文秀','元','元曲','yuanqu','','[]','这言语没掂三，可知水深把杖儿探。',31,'元曲/yuanqu.json','["这言语没掂三，可知水深把杖儿探。", "对君王休把平人陷，赵元酒性腌。"]'),
('yuanqu-4099','好酒赵元遇上皇・甜水令','高文秀','元','元曲','yuanqu','','[]','臣一心不恋高官，不图富贵，休将人赚，这烦恼怎生担？（驾云）寡人与你修盖宅舍，建立厅堂。',75,'元曲/yuanqu.json','["臣一心不恋高官，不图富贵，休将人赚，这烦恼怎生担？（驾云）寡人与你修盖宅舍，建立厅堂。", "（正末唱）也不索建立厅堂，修盖宅合，妆銮堆嵌，不如我住草舍茅庵。"]'),
('yuanqu-4100','好酒赵元遇上皇・七弟兄','高文秀','元','元曲','yuanqu','','[]','微臣怎敢把大官参，我则知苦涩酸浑淡。',64,'元曲/yuanqu.json','["微臣怎敢把大官参，我则知苦涩酸浑淡。", "清光滑辣任迷贪，下民易虐何曾滥？（驾云）寡人欲要封你为官，为何推托？公有主意也。", "（正末唱）。"]'),
('yuanqu-4101','好酒赵元遇上皇・梅花酒','高文秀','元','元曲','yuanqu','','[]','呀！微臣最小胆，则待逐日醺酣，圣主台鉴，你两两三三。',91,'元曲/yuanqu.json','["呀！微臣最小胆，则待逐日醺酣，圣主台鉴，你两两三三。", "也不做明廉共按察，伯子共公男。", "自羞惭，官高后不心甘，禄重也自贪婪。", "（驾云）明廉按察，你又不做。", "似这等，你待做甚么官好？（正末唱）。"]'),
('yuanqu-4102','好酒赵元遇上皇・收江南','高文秀','元','元曲','yuanqu','','[]','我汴梁城则做酒都监，自斟自舞自清谈，无烦无恼口劳蓝。',44,'元曲/yuanqu.json','["我汴梁城则做酒都监，自斟自舞自清谈，无烦无恼口劳蓝。", "是非处没俺，这玉堂食怎如我瓮头甘？。"]'),
('yuanqu-4103','好酒赵元遇上皇・雁儿落','高文秀','元','元曲','yuanqu','','[]','姜太公颠倒敢，鲁义姑心中鉴。',29,'元曲/yuanqu.json','["姜太公颠倒敢，鲁义姑心中鉴。", "倚官府要了手模，你今日遭坑陷。"]'),
('yuanqu-4104','双调・新水令春情','程景初','元','元曲','yuanqu','','[]','落红满地暮春天，另一番蜂愁蝶怨。',35,'元曲/yuanqu.json','["落红满地暮春天，另一番蜂愁蝶怨。", "愁切切，恨绵绵。", "待要团圆，除非梦中见。"]'),
('yuanqu-4105','驻马听・小小亭轩，燕子来时帘未卷。深庭小院，杜鹃啼处月空圆。金钗','程景初','元','元曲','yuanqu','','[]','拨尽玉炉烟，香尘渍满琵琶面。',27,'元曲/yuanqu.json','["拨尽玉炉烟，香尘渍满琵琶面。", "谁共言？何时枕匾黄金钏？。"]'),
('yuanqu-4107','落梅风・鸾钗断，凤髻偏，腻残妆泪痕满面。隔纱窗消声儿唤玉莲，那人','程景初','元','元曲','yuanqu','','[]','儿敢有些爻变。',7,'元曲/yuanqu.json','["儿敢有些爻变。"]'),
('yuanqu-4108','南吕・一枝花','张彦文','元','元曲','yuanqu','','[]','春风醉碧桃，流水题红叶。',57,'元曲/yuanqu.json','["春风醉碧桃，流水题红叶。", "只因闲信马，为此误随车。", "妆氵井妆呆，一笑千金舍。", "痴心不暂歇，经了些欢聚愁别，情债填还未彻。"]'),
('yuanqu-4109','牧羊关・天边凤，花上蝶，才伶俐又还粘惹。都因眼约心期，引斗得肠怀','张彦文','元','元曲','yuanqu','','[]','腹热。',27,'元曲/yuanqu.json','["腹热。", "云雨新情重，风月旧恩绝。", "翡翠合欢带，鸳鸯交颈结。"]'),
('yuanqu-4110','随煞・亏心底自有神夭折，薄幸教随唾津儿灭。休道你花朵儿般身躯没凋','张彦文','元','元曲','yuanqu','','[]','谢，你个聪明的小姐宁心儿记者：咱这说下的盟言应去也。',26,'元曲/yuanqu.json','["谢，你个聪明的小姐宁心儿记者：咱这说下的盟言应去也。"]'),
('yuanqu-4111','仙吕・醉扶归','吕止庵','元','元曲','yuanqu','','[]','瘦后因他瘦，愁后为他愁。',138,'元曲/yuanqu.json','["瘦后因他瘦，愁后为他愁。", "早知伊家不应口，谁肯先成就。", "营勾了人也罢手，吃得我些酩子里骂低低的咒。", "频去教人讲，不去自家忙。", "若得相思海上方，不到得害这些闲魔障。", "你笑我眠思梦想，则不打到你头直上。", "有意同成就，无意大家休。", "几度相思几度愁，风月虚遥授。", "你若肯时肯不肯时罢手，休把人空拖逗。"]'),
('yuanqu-4112','商调・知秋令为董针姑作','吕止庵','元','元曲','yuanqu','','[]','心间事，肠断时，醉墨写乌丝。',133,'元曲/yuanqu.json','["心间事，肠断时，醉墨写乌丝。", "千金字，织锦词。", "绣针儿，不比莺儿燕子。", "相思病，万种情，几度海山盟。", "谁薄幸？谁至诚？更能行，到底如何离影？情如醉，闷似痴，春瘦怯春衣。", "添憔悴，废寝食。", "减腰肢，怎脱厌厌病体？千金字，万古心，翻作断肠吟。", "恩情厚，怨恨深。", "不知音，谁会重拈绣针？。"]'),
('yuanqu-4113','越调・天净沙为董针姑作','吕止庵','元','元曲','yuanqu','','[]','夜深时独绣罗鞋，不言语倒在人怀，做意儿将人不采。',152,'元曲/yuanqu.json','["夜深时独绣罗鞋，不言语倒在人怀，做意儿将人不采。", "甚娘作怪，绣针儿签着敲才。", "海棠轻染胭脂，绿杨乱撒青丝，对对莺儿燕子。", "伤心独自，绣针儿停待多时。", "玉纤屈损春葱，远山压损眉峰，早是闲愁万种。", "忽听得卖花声送，绣针儿不待穿绒。", "冷清清独守兰房，闷恹恹倚定纱窗，呆答孩搭伏定绣床。", "一会家神魂飘荡，绣针儿签这梅香。", "套数。"]'),
('yuanqu-4115','翠裙腰・老来多病逢秋验，便觉嫩凉添，懒摇纨扇闲纹簟。卷朱帘，晚妆','吕止庵','元','元曲','yuanqu','','[]','楼外月纤纤。',6,'元曲/yuanqu.json','["楼外月纤纤。"]'),
('yuanqu-4116','金盏儿・更西风酽，微云敛。黄昏即渐，暑气消沛。阴晴乍闪，冰魂尚潜。','吕止庵','元','元曲','yuanqu','','[]','指甲痕芽天生堑，双帘，又传宫样印眉尖。',19,'元曲/yuanqu.json','["指甲痕芽天生堑，双帘，又传宫样印眉尖。"]'),
('yuanqu-4117','元和令・素娥公案严，牛女分缘俭。苍虬钩玉控雕檐，翠屏人半掩。彩鸾','吕止庵','元','元曲','yuanqu','','[]','收镜入妆奁，霓裳谁再拈？。',13,'元曲/yuanqu.json','["收镜入妆奁，霓裳谁再拈？。"]'),
('yuanqu-4118','赚尾・昂藏醉脸，桂香襟袖沾。花下心无慊，樽前兴未厌。钓银蟾，瑶台','吕止庵','元','元曲','yuanqu','','[]','独占，立金梯长笑一掀髯。',12,'元曲/yuanqu.json','["独占，立金梯长笑一掀髯。"]'),
('yuanqu-4119','商调・集贤宾叹世','吕止庵','元','元曲','yuanqu','','[]','叹浮生有如一梦里，将往事已成非。',83,'元曲/yuanqu.json','["叹浮生有如一梦里，将往事已成非。", "迅指间红轮西坠，霎时间沧海尘飞。", "正青春绿鬓斑皤，恰朱颜皓首庞眉，转回头都做了北邙山下鬼。", "题起来总是伤悲，都不如酒淹衫袖湿，花压帽檐低。"]'),
('yuanqu-4120','逍遥乐・有何拘系，则不如一枕安然，直睡到红日三竿未起。乐吾心诗酒','吕止庵','元','元曲','yuanqu','','[]','琴棋，守团圆稚子山妻。',45,'元曲/yuanqu.json','["琴棋，守团圆稚子山妻。", "富贵功名身外礼，懒营求免受驱驰。", "则不如放怀遣兴，悦性怡情，展眼舒眉。"]'),
('yuanqu-4121','梧叶儿・争甚名和利，问甚么我共你。咱人可也转眼故人稀，渐渐的将朱','吕止庵','元','元曲','yuanqu','','[]','颜换，看看的早白发催。',29,'元曲/yuanqu.json','["颜换，看看的早白发催。", "题起来好伤悲，赤紧的当不住白驹过隙。"]'),
('yuanqu-4122','双雁儿・不如闻早去来兮，乐清闲穷究理，无辱无荣不萦系。守清贫绝是','吕止庵','元','元曲','yuanqu','','[]','非，远红尘参道德。',9,'元曲/yuanqu.json','["非，远红尘参道德。"]'),
('yuanqu-4123','醋葫芦・到春来听黄莺枝上鸣，闻杜鹃花下啼。声声叫道不如归，囊中钱','吕止庵','元','元曲','yuanqu','','[]','劝君休爱惜。',25,'元曲/yuanqu.json','["劝君休爱惜。", "拚了个醉而醒醒而复醉，席前花影坐间移。"]'),
('yuanqu-4124','幺・到夏来看湖光潋滟生，香风处处微。披襟散发绿杨堤，得一日过一日','吕止庵','元','元曲','yuanqu','','[]','无了一日。',19,'元曲/yuanqu.json','["无了一日。", "争何名利，想人生自古七十稀。"]'),
('yuanqu-4125','幺・到秋来看东篱菊绽金，玩长天月似水。正江涵秋景雁初飞，乐吾心笑','吕止庵','元','元曲','yuanqu','','[]','谈饮数杯。',19,'元曲/yuanqu.json','["谈饮数杯。", "酒逢知契，把黄花乱插满头归。"]'),
('yuanqu-4126','幺・到冬来落琼花阵阵飘，剪鹅毛片片飞。横窗梅影映疏篱，草堂中满斟','吕止庵','元','元曲','yuanqu','','[]','酒数杯。',21,'元曲/yuanqu.json','["酒数杯。", "醉时节盹睡，一任教红尘滚滚往来飞。"]'),
('yuanqu-4127','尾声・蜗角名休苦贪，蝇头利总休觅。鹤长凫短不能齐，到头来不知谁是','吕止庵','元','元曲','yuanqu','','[]','我则待混俗为最，总不如葫芦今后大家提。',19,'元曲/yuanqu.json','["我则待混俗为最，总不如葫芦今后大家提。"]'),
('yuanqu-4128','双调・夜行船咏金莲','吕止庵','元','元曲','yuanqu','','[]','颜色天然风韵佳，据精神闭月羞花。',33,'元曲/yuanqu.json','["颜色天然风韵佳，据精神闭月羞花。", "腻粉妆，施匀罢，风流处那些儿堪画。"]'),
('yuanqu-4129','步步娇・微露金莲唐裙下，端的是些娘大，刚半札。若舞霓裳将翠盘踏，','吕止庵','元','元曲','yuanqu','','[]','若是觑绝他，不让杨妃袜。',12,'元曲/yuanqu.json','["若是觑绝他，不让杨妃袜。"]'),
('yuanqu-4130','沉醉东风・那步轻轻慢撒，移踪款款微踏。或是到晚夕，临床榻，拥鲛绡','吕止庵','元','元曲','yuanqu','','[]','枕边灯下。',21,'元曲/yuanqu.json','["枕边灯下。", "那的是冤家痛紧恰，脱了鞋儿缠咱。"]'),
('yuanqu-4131','拨不断・为冤家，恨咱家。三兜根用意收拾煞，缠得上十分紧恰。怕松时','吕止庵','元','元曲','yuanqu','','[]','重套上吴绫袜，从缠上几时撇下。',15,'元曲/yuanqu.json','["重套上吴绫袜，从缠上几时撇下。"]'),
('yuanqu-4132','双调・风入松','吕止庵','元','元曲','yuanqu','','[]','半生花柳稍曾耽，风月畅尴尬。',44,'元曲/yuanqu.json','["半生花柳稍曾耽，风月畅尴尬。", "付能巴到蓝桥驿，不堤防烟水重淹。", "追想盟山誓海，几度泪湿青衫。"]'),
('yuanqu-4134','新水令・巧盘云髻插琼簪，穿一套素衣恁般甜淡。他说得话儿岩，合下手','吕止庵','元','元曲','yuanqu','','[]','脾和，莫不是把人赚？。',11,'元曲/yuanqu.json','["脾和，莫不是把人赚？。"]'),
('yuanqu-4135','搅筝琶・闲言探，切恐话交参。休道咱虚，怕伊不敢。岂怕外人知，只恐','吕止庵','元','元曲','yuanqu','','[]','娘监。',17,'元曲/yuanqu.json','["娘监。", "离恨闷愁两下耽，独自个羞惨。"]'),
('yuanqu-4136','离亭宴歇指煞・做时节彼各休心厌，做时节休把人坑陷。常欢喜星前月下，','吕止庵','元','元曲','yuanqu','','[]','休等闲间面北眉南。',42,'元曲/yuanqu.json','["休等闲间面北眉南。", "既做时休忐忑，若意懒后众生便减。", "我着片无忝和朴实心，博伊家做怪胆。"]'),
('yuanqu-4137','正宫・端正好美妓','吴昌龄','元','元曲','yuanqu','','[]','墨点柳眉新，酒晕桃腮嫩，破春娇半颗朱唇，海棠颜色红霞韵。',34,'元曲/yuanqu.json','["墨点柳眉新，酒晕桃腮嫩，破春娇半颗朱唇，海棠颜色红霞韵。", "宫额芙蓉印。"]'),
('yuanqu-4138','滚绣球・藕丝裳翡翠裙，芭蕉扇竹叶樽。衬缃裙玉钩三寸，露春葱十指如','吴昌龄','元','元曲','yuanqu','','[]','秋波两点真，春山八字分。',49,'元曲/yuanqu.json','["秋波两点真，春山八字分。", "颤巍巍雾鬟云鬓，胭脂颈玉软香温。", "轻拈翠靥花生晕，斜插犀梳月破云。", "误落风尘。"]'),
('yuanqu-4139','倘秀才・莫不是丽春园苏乡的后身，多应是西厢下莺莺的影神，便有丹青','吴昌龄','元','元曲','yuanqu','','[]','画不真。',25,'元曲/yuanqu.json','["画不真。", "妆梳诸样巧，笑语暗生春。", "他有那千般儿可人。"]'),
('yuanqu-4140','脱布衫・常记的五言诗暗寄回文，千金夜古断青春。厮陪奉娇香腻粉，喜','吴昌龄','元','元曲','yuanqu','','[]','相逢柳营花阵。',7,'元曲/yuanqu.json','["相逢柳营花阵。"]'),
('yuanqu-4141','醉太平・这些时春寒绣ブ，月暗重门，梨花暮雨近黄昏，把香衾自温。金','吴昌龄','元','元曲','yuanqu','','[]','杯不洗心头闷，青鸾不寄云边信，玉容不见意中人。',29,'元曲/yuanqu.json','["杯不洗心头闷，青鸾不寄云边信，玉容不见意中人。", "空教人害损。"]'),
('yuanqu-4142','随煞・想当日一宵欢会成秦晋，翻做了千里关山劳梦魂。漏永更长烛影昏，','吴昌龄','元','元曲','yuanqu','','[]','柳暗花遮曙色分。',46,'元曲/yuanqu.json','["柳暗花遮曙色分。", "酒酽花浓锦帐新，倚玉偎红翠被温。", "有一日重会菱花镜里人，将我这受过凄凉正了本。"]'),
('yuanqu-4143','中吕・粉蝶儿集中州韵','黑老五','元','元曲','yuanqu','','[]','从东陇风动松呼，听叮咛定睛睁觑，望苍谩钝广黄芦。',54,'元曲/yuanqu.json','["从东陇风动松呼，听叮咛定睛睁觑，望苍谩钝广黄芦。", "却樵夫，遇渔父，递知机携物。", "便盘旋千转前湖，看寒山晚关滩渡。"]'),
('yuanqu-4144','红绣鞋・才在怪歪崖捱步，磨过多过河渠，野赊斜隔这些疏。沉吟林阴阻，','黑老五','元','元曲','yuanqu','','[]','甘探淡淡儒，趁村门人问取。',13,'元曲/yuanqu.json','["甘探淡淡儒，趁村门人问取。"]'),
('yuanqu-4145','十二月・小鸟鹊高巢梢噪呼，骑一骑急喜避崎岖。乌酥土枯湖古渡，岚惨','黑老五','元','元曲','yuanqu','','[]','淡庵勘堪图。',22,'元曲/yuanqu.json','["淡庵勘堪图。", "看看晚残山慢阻，忙忙莽望穰荒伏。"]'),
('yuanqu-4146','尧民歌・呀，陇东哄贡冲松动猛风毒，自姿尔思此诗赋。蓝关暂俺暗参吾，','黑老五','元','元曲','yuanqu','','[]','那家他把夹芭居。',27,'元曲/yuanqu.json','["那家他把夹芭居。", "抽首就踌躇，裁划该载孤，闷昏奔村门去。"]'),
('yuanqu-4147','耍孩儿・盘桓疃畔峦端路，见一个绕倒忉骚老夫。穿一领袖头露肘旧绸服，','黑老五','元','元曲','yuanqu','','[]','骑一匹便鞭扌扇蹇嫣驴。',55,'元曲/yuanqu.json','["骑一匹便鞭扌扇蹇嫣驴。", "轻行停省惊睁目，迤<辶里>即迷失记途，多因是抹坡错过多过阻。", "虫蛩蜂丛猛动，禽吟林阴荫疏。"]'),
('yuanqu-4148','四煞・那厮儿拿瓜那塔要这老儿近身频问取，那厮儿故徒不顾都胡觑；那','黑老五','元','元曲','yuanqu','','[]','老儿欠谦廉俭粘拈絮，那厮儿奸亻孱还顽懒惮语。',50,'元曲/yuanqu.json','["老儿欠谦廉俭粘拈絮，那厮儿奸亻孱还顽懒惮语。", "缠绵转见涎天暮，那厮儿始使兹之指视，这老儿既知喜己眉舒。"]'),
('yuanqu-4149','煞尾・那厮儿本分蠢钝淳，这老儿别也扯柘苦。听称名姓叮咛诉，则向那','黑老五','元','元曲','yuanqu','','[]','聚旅无虞去处宿。',8,'元曲/yuanqu.json','["聚旅无虞去处宿。"]'),
('yuanqu-4150','张君瑞庆团园(第五本)・仙吕/赏花时','王实甫','元','元曲','yuanqu','','[]','相见时红雨纷纷点绿苔，别离后黄叶萧萧凝暮霭。',81,'元曲/yuanqu.json','["相见时红雨纷纷点绿苔，别离后黄叶萧萧凝暮霭。", "今日见梅开，别离半载。", "琴童，我嘱咐你的言语记着！则说道特地寄书来。", "(下)(仆云)得了这书，星夜望河中府走一遭。", "(下)。"]'),
('yuanqu-4151','张君瑞庆团园(第五本)・商调/集贤宾','王实甫','元','元曲','yuanqu','','[]','虽离了我眼前，却在心上有；不甫能离了心上，又早眉头。',93,'元曲/yuanqu.json','["虽离了我眼前，却在心上有；不甫能离了心上，又早眉头。", "忘了时依然还又，恶思量无了无休。", "大都来一寸眉峰，怎咋他许多颦皱。", "新愁近来接着旧愁，厮混了难分新旧。", "旧愁似太行山隐隐，新愁似天堑水悠悠。"]'),
('yuanqu-4152','张君瑞庆团园(第五本)・逍遥乐','王实甫','元','元曲','yuanqu','','[]','曾经消瘦，每遍犹闲，这番最陡。',124,'元曲/yuanqu.json','["曾经消瘦，每遍犹闲，这番最陡。", "(红云)姐姐心儿闷呵，那里散心耍咱。", "(旦唱)何处忘忧？看时节独上妆楼，手卷珠帘上玉钩，空目断山明水秀；见苍烟迷树，衰草连天，野渡横舟。", "(旦云)红娘，我这衣裳这些时都不似我穿的。", "(红云)姐姐正是\"腰细不胜衣\"。", "(旦唱)。"]'),
('yuanqu-4153','张君瑞庆团园(第五本)・挂金索','王实甫','元','元曲','yuanqu','','[]','裙染榴花，睡损胭脂皱；纽结丁香，掩过芙蓉扣；线脱珍珠，泪湿香罗袖；杨柳眉颦，"人比黄花瘦"。',46,'元曲/yuanqu.json','["裙染榴花，睡损胭脂皱；纽结丁香，掩过芙蓉扣；线脱珍珠，泪湿香罗袖；杨柳眉颦，\"人比黄花瘦\"。"]'),
('yuanqu-4154','张君瑞庆团园(第五本)・金菊花','王实甫','元','元曲','yuanqu','','[]','早是我只因他去减了风流，不争你寄得书来又与我添些儿症候。',50,'元曲/yuanqu.json','["早是我只因他去减了风流，不争你寄得书来又与我添些儿症候。", "说来的话儿不应口，无语低头，书在手，泪凝眸。"]'),
('yuanqu-4155','张君瑞庆团园(第五本)・醋葫芦','王实甫','元','元曲','yuanqu','','[]','我这里开时和泪开，他那些修时和泪修。',65,'元曲/yuanqu.json','["我这里开时和泪开，他那些修时和泪修。", "多管阁着笔尖儿未写早泪先流，寄来的书泪点儿兀自有。", "我将这新痕把旧痕湮透。", "正是一重愁翻做两重愁。"]'),
('yuanqu-4156','张君瑞庆团园(第五本)・梧叶儿','王实甫','元','元曲','yuanqu','','[]','他若是和衣卧，便是和我一处宿；但贴着他皮肉，不信不想我温柔。',90,'元曲/yuanqu.json','["他若是和衣卧，便是和我一处宿；但贴着他皮肉，不信不想我温柔。", "(红云)这裹牡要怎么？(旦唱)常则不要离了前后，守着他左右。", "紧紧的系在心头。", "(红云)这袜儿如何？(旦唱)拘管他胡行乱走。"]'),
('yuanqu-4157','张君瑞庆团园(第五本)・后庭花','王实甫','元','元曲','yuanqu','','[]','当日五言诗紧趁逐，后来因七弦琴成配偶。',133,'元曲/yuanqu.json','["当日五言诗紧趁逐，后来因七弦琴成配偶。", "他怎旨冷落了诗中意，我则怕生疏了弦上。", "(红云)玉簪呵有甚主意？(旦唱)我须有个缘由，他如今功名成就，又怕他撇人在脑背后。", "(红云)斑管要怎的？(旦唱)湘江两岸秋，当日娥皇因虞舜愁，今日莺莺为君瑞忧。", "这九嶷山下竹，共香罗衫袖口--。"]'),
('yuanqu-4158','张君瑞庆团园(第五本)・青哥儿','王实甫','元','元曲','yuanqu','','[]','都一般啼痕湮透。',53,'元曲/yuanqu.json','["都一般啼痕湮透。", "似这等泪斑斑宛然依旧，万古情缘一样愁。", "涕泪交流，怨慕难收，对学士叮咛说缘由，是必休忘旧！。"]'),
('yuanqu-4159','张君瑞庆团园(第五本)・醋葫芦','王实甫','元','元曲','yuanqu','','[]','你逐宵野店上宿，休将包袱做枕头，怕油脂腻展污了恐难酬。',59,'元曲/yuanqu.json','["你逐宵野店上宿，休将包袱做枕头，怕油脂腻展污了恐难酬。", "倘或水侵雨湿休便扭，我则怕干时节熨不开褶皱。", "一桩桩一件件细收留。"]'),
('yuanqu-4160','张君瑞庆团园(第五本)・金菊花','王实甫','元','元曲','yuanqu','','[]','书封雁足此时修，情系人心早晚休？长安望来天际头，倚遍西楼，"人不见，水空流。',81,'元曲/yuanqu.json','["书封雁足此时修，情系人心早晚休？长安望来天际头，倚遍西楼，\"人不见，水空流。", "\"(仆云)小人拜辞，即便去也。", "(旦云)琴童，你见官人对他说。", "(仆云)说甚么？(旦唱)。"]'),
('yuanqu-4161','张君瑞庆团园(第五本)・浪里来煞','王实甫','元','元曲','yuanqu','','[]','他那里为我愁，我这里因他瘦。',80,'元曲/yuanqu.json','["他那里为我愁，我这里因他瘦。", "临行时啜赚人的巧舌头，指归期约定九月九，不觉的过了小春时候。", "到如今\"悔教夫婿觅封侯\"。", "(仆云)得了回书，星夜回俺哥哥话去。", "(并下)。"]'),
('yuanqu-4162','张君瑞庆团园(第五本)・中吕/粉蝶儿','王实甫','元','元曲','yuanqu','','[]','从到京师，思量心旦夕如是，向心头横躺着俺那莺儿。',55,'元曲/yuanqu.json','["从到京师，思量心旦夕如是，向心头横躺着俺那莺儿。", "请医师，看诊罢，一星星说是。", "本意待推辞，则被他察虚实不须看视。"]'),
('yuanqu-4163','张君瑞庆团园(第五本)・醉春风','王实甫','元','元曲','yuanqu','','[]','他道是医杂症有方术，治相思无药饵。',53,'元曲/yuanqu.json','["他道是医杂症有方术，治相思无药饵。", "莺莺呵，你若是知我害相思，我甘心儿死、死。", "四海无家，一身客寄，半年将至。"]'),
('yuanqu-4164','张君瑞庆团园(第五本)・迎仙客','王实甫','元','元曲','yuanqu','','[]','疑怪这噪花枝灵鹊儿，垂帘幕喜蛛儿，正应着短檠上夜来灯爆时。',329,'元曲/yuanqu.json','["疑怪这噪花枝灵鹊儿，垂帘幕喜蛛儿，正应着短檠上夜来灯爆时。", "若不是断肠词，决定是断肠诗。", "(仆去)小夫人有书至此。", "(末接科)写时管情泪如丝，既不呵，怎生泪点儿封皮上渍。", "(末读书科)\"薄命妾崔氏拜覆，敬奉才郎君瑞文几：自音容去后，不觉许时，仰敬之心，未尝少怠。", "纵云日近长安远，何故鳞鸿之杳矣。", "莫因花柳之心，弃妾恩情之意？正念问，琴童至，得见翰墨，始知中科，使妾喜之如狂。", "郎之才望，亦不辱相国之家谱也。", "今因琴童回，无以奉贡，聊布瑶琴一张，玉簪一枝，斑管一枚，裹肚一条，汗衫一领，袜儿一双，权表妾之真诚。", "匆匆草字欠恭，伏乞情恕不备。", "谨依来韵，遂继一绝云：阑干倚遍盼才郎，莫恋宸京黄四娘；病里得书知中甲，窗前鉴镜试新妆\"。", "那风风流流的姐姐，似这等女子，张珙死也死得着了。"]'),
('yuanqu-4165','张君瑞庆团园(第五本)・上小楼','王实甫','元','元曲','yuanqu','','[]','这的堪为字史，当为款识。',49,'元曲/yuanqu.json','["这的堪为字史，当为款识。", "有柳骨颜筋，张旭张颠，羲之献之。", "此一时，彼一时，佳人才思，俺莺莺世间无二。"]'),
('yuanqu-4166','张君瑞庆团园(第五本)・幺篇','王实甫','元','元曲','yuanqu','','[]','俺做经咒般持，符篆般使。',85,'元曲/yuanqu.json','["俺做经咒般持，符篆般使。", "高似金章，重似金帛，贵似金资。", "这上面若签个押字，使个令史，差个勾使，则是一张忙不及印赴期的咨示。", "(末拿汗衫儿科)休道文章，只看他这针指，人间少有。"]'),
('yuanqu-4167','张君瑞庆团园(第五本)・满庭芳','王实甫','元','元曲','yuanqu','','[]','怎不教张生爱尔，堪针工出色，女教为师。',71,'元曲/yuanqu.json','["怎不教张生爱尔，堪针工出色，女教为师。", "几千般用意针针是，可索寻思。", "长共短又没个样子，窄和宽想像著腰肢，好共歹无人试。", "想当初做时，用煞那小心儿。"]'),
('yuanqu-4168','张君瑞庆团园(第五本)・白鹤子','王实甫','元','元曲','yuanqu','','[]','这琴，他教我闭门学禁指，留意谱声诗，调养圣贤心，洗荡巢由耳。',30,'元曲/yuanqu.json','["这琴，他教我闭门学禁指，留意谱声诗，调养圣贤心，洗荡巢由耳。"]'),
('yuanqu-4169','张君瑞庆团园(第五本)・三煞','王实甫','元','元曲','yuanqu','','[]','这斑管，霜枝曾栖凤凰，泪点渍胭脂。',33,'元曲/yuanqu.json','["这斑管，霜枝曾栖凤凰，泪点渍胭脂。", "当时舜帝恸娥皇，今日淑女思君子。"]'),
('yuanqu-4170','张君瑞庆团园(第五本)・四煞','王实甫','元','元曲','yuanqu','','[]','这裹肚，手中一叶绵，灯下几回丝；表出腹中愁，果称心间事。',28,'元曲/yuanqu.json','["这裹肚，手中一叶绵，灯下几回丝；表出腹中愁，果称心间事。"]'),
('yuanqu-4171','张君瑞庆团园(第五本)・五煞','王实甫','元','元曲','yuanqu','','[]','这鞋袜儿，针脚儿细似虮子，绢帛儿腻似鹅脂。',63,'元曲/yuanqu.json','["这鞋袜儿，针脚儿细似虮子，绢帛儿腻似鹅脂。", "既知礼不胡行，愿足下当如此。", "琴童，你临行小夫人对你说甚么？(仆云)着哥哥休别继良姻。"]'),
('yuanqu-4172','张君瑞庆团园(第五本)・快活三','王实甫','元','元曲','yuanqu','','[]','冷清清客店儿，风淅淅雨丝。',32,'元曲/yuanqu.json','["冷清清客店儿，风淅淅雨丝。", "雨儿零，风儿细，梦回时，多少伤，心事。"]'),
('yuanqu-4173','张君瑞庆团园(第五本)・朝天子','王实甫','元','元曲','yuanqu','','[]','四肢不能动止，急切里盼不到蒲东寺。',68,'元曲/yuanqu.json','["四肢不能动止，急切里盼不到蒲东寺。", "小夫人须是你见时，别有其闲传示？我是个浪子官人，风流学士，怎肯去带残花折旧枝。", "自从到此，甚的是闲街市。"]'),
('yuanqu-4174','张君瑞庆团园(第五本)・贺圣朝','王实甫','元','元曲','yuanqu','','[]','少甚宰相人家，招婿的娇姿。',51,'元曲/yuanqu.json','["少甚宰相人家，招婿的娇姿。", "其间或有个人儿似尔，那里取那温柔，这般才思？想莺莺意儿，怎不教人梦想眠思？。"]'),
('yuanqu-4175','张君瑞庆团园(第五本)・二煞','王实甫','元','元曲','yuanqu','','[]','恰新婚，才燕尔，为功名来到此，长安忆念蒲东寺。',59,'元曲/yuanqu.json','["恰新婚，才燕尔，为功名来到此，长安忆念蒲东寺。", "昨宵个春风桃李花开夜，今日个秋雨梧桐叶落时。", "愁如是，身遥心迩，坐想行思。"]'),
('yuanqu-4176','张君瑞庆团园(第五本)・三煞','王实甫','元','元曲','yuanqu','','[]','这天高地厚情，直到海枯石烂时，此时作念何时止？直到灯灰眼下才无泪，蚕老心中罢却丝。',64,'元曲/yuanqu.json','["这天高地厚情，直到海枯石烂时，此时作念何时止？直到灯灰眼下才无泪，蚕老心中罢却丝。", "我不比游荡轻薄子，轻夫妇的琴瑟，拆恋凤的雄雌。"]'),
('yuanqu-4177','张君瑞庆团园(第五本)・四煞','王实甫','元','元曲','yuanqu','','[]','不闻黄犬音，难传红叶诗，驿长不遇梅花使。',52,'元曲/yuanqu.json','["不闻黄犬音，难传红叶诗，驿长不遇梅花使。", "孤身去国三千里，一日归心十二时。", "凭栏视，听江声浩荡，看山色参差。"]'),
('yuanqu-4178','张君瑞庆团园(第五本)・尾','王实甫','元','元曲','yuanqu','','[]','忧则忧我在病中，喜则喜你来到此，投至得引人魂卓氏音书至，险将这害鬼病的相如盼望死，(下)。',45,'元曲/yuanqu.json','["忧则忧我在病中，喜则喜你来到此，投至得引人魂卓氏音书至，险将这害鬼病的相如盼望死，(下)。"]'),
('yuanqu-4179','张君瑞庆团园(第五本)・天净沙','王实甫','元','元曲','yuanqu','','[]','看河桥飞虎将军，叛蒲东掳掠人民，半万贼屯合寺门，手横着霜刃，高叫道要莺莺做压寨夫人。',42,'元曲/yuanqu.json','["看河桥飞虎将军，叛蒲东掳掠人民，半万贼屯合寺门，手横着霜刃，高叫道要莺莺做压寨夫人。"]'),
('yuanqu-4180','张君瑞庆团园(第五本)・小桃红','王实甫','元','元曲','yuanqu','','[]','洛阳才子善属文，火急修书信。',105,'元曲/yuanqu.json','["洛阳才子善属文，火急修书信。", "白马将军到时分，灭了烟尘。", "夫人小姐都心顺，则为他\"威而不猛\"，\"言而有信\"，因此上\"不敢慢于人\"。", "(净云)我自来未尝闻其名，知他会也不会。", "你这个小妮子，卖弄他偌多！(红云)便又骂我。"]'),
('yuanqu-4181','张君瑞庆团园(第五本)・金蕉叶','王实甫','元','元曲','yuanqu','','[]','他凭着讲性理齐论鲁论，作词赋韩文柳文，他识道理为人敬人，掩家里有信行知恩报恩。',39,'元曲/yuanqu.json','["他凭着讲性理齐论鲁论，作词赋韩文柳文，他识道理为人敬人，掩家里有信行知恩报恩。"]'),
('yuanqu-4182','张君瑞庆团园(第五本)・调笑令','王实甫','元','元曲','yuanqu','','[]','你值一分，他值百十分，萤火焉能比月轮？高低远近都休论，我拆白道字辨与你个清浑。',99,'元曲/yuanqu.json','["你值一分，他值百十分，萤火焉能比月轮？高低远近都休论，我拆白道字辨与你个清浑。", "(净云)这小妮子首得甚么拆白道字，你拆与我听。", "(红唱)君瑞是个\"肖\"字这壁着个\"立人\"，你是个\"木寸\"\"马户\"\"尸巾\"。"]'),
('yuanqu-4183','张君瑞庆团园(第五本)・秃厮儿','王实甫','元','元曲','yuanqu','','[]','他凭师友君子务本，你倚父兄仗势欺人。',35,'元曲/yuanqu.json','["他凭师友君子务本，你倚父兄仗势欺人。", "齑盐日月不嫌贫，治百姓新传、传闻。"]'),
('yuanqu-4184','张君瑞庆团园(第五本)・圣药王','王实甫','元','元曲','yuanqu','','[]','这厮乔议论，有向顺。',50,'元曲/yuanqu.json','["这厮乔议论，有向顺。", "你道是官人则合做官人，信口喷，不本分。", "你道穷民到老是穷民，却不道\"将相出寒门\"。"]'),
('yuanqu-4186','张君瑞庆团园(第五本)・幺篇','王实甫','元','元曲','yuanqu','','[]','讪筋，发村，使狠，甚的是软款温存。',33,'元曲/yuanqu.json','["讪筋，发村，使狠，甚的是软款温存。", "硬打捱强为眷姻，不睹事强谐秦晋。"]'),
('yuanqu-4187','张君瑞庆团园(第五本)・络丝娘','王实甫','元','元曲','yuanqu','','[]','你须是郑相国嫡亲的舍人。',44,'元曲/yuanqu.json','["你须是郑相国嫡亲的舍人。", "须不是孙飞虎家生的莽军。", "乔嘴脸、腌躯老、死身分，少不得有家难奔。"]'),
('yuanqu-4188','张君瑞庆团园(第五本)・双调/新水令','王实甫','元','元曲','yuanqu','','[]','玉鞭骄马出皇都，畅风流玉堂人物。',40,'元曲/yuanqu.json','["玉鞭骄马出皇都，畅风流玉堂人物。", "今朝三品职，昨日一寒儒。", "御笔亲除，将名姓翰林注。"]'),
('yuanqu-4189','张君瑞庆团园(第五本)・驻马听','王实甫','元','元曲','yuanqu','','[]','张珙如愚，酬志了三尺龙泉万卷书；莺莺有福。',122,'元曲/yuanqu.json','["张珙如愚，酬志了三尺龙泉万卷书；莺莺有福。", "稳请了五花官诰七香七。", "身荣难忘借僧居，愁来犹记题诗处。", "从应举，梦魂儿不离了蒲东路。", "(末云)接了马者(见夫人科)新状元河中府尹婿张珙参见。", "(夫人云)休拜，休拜，你是女圣旨的女婿，我怎消受得你拜？(末唱)。"]'),
('yuanqu-4190','张君瑞庆团园(第五本)・乔牌儿','王实甫','元','元曲','yuanqu','','[]','我躬身问起居，夫人这慈色为谁怒？我则见丫环使数邢厮觑，莫不我身边有甚事故？(末云)小生去时，人人亲自饯行，喜不自胜。',197,'元曲/yuanqu.json','["我躬身问起居，夫人这慈色为谁怒？我则见丫环使数邢厮觑，莫不我身边有甚事故？(末云)小生去时，人人亲自饯行，喜不自胜。", "今日中选得百，夫人反行不悦，何也？(夫人云)你如今那里想着俺家？道不得个\"靡不有初，鲜克有终\"。", "我一个女孩儿，虽然妆残貌陋，他父为前朝相国。", "若非贼来，足下甚气力到得俺家？今日一旦置之度外，却于卫尚书家作婿，岂有是理？(末云)夫人听谁说？若有此事，天不盖，地不载，害老大小疗疮！。"]'),
('yuanqu-4191','张君瑞庆团园(第五本)・雁儿落','王实甫','元','元曲','yuanqu','','[]','若说着丝鞭仕女图，端的是塞满章台路。',36,'元曲/yuanqu.json','["若说着丝鞭仕女图，端的是塞满章台路。", "小生呵此间怀旧恩，怎肯别处寻亲去？。"]'),
('yuanqu-4192','张君瑞庆团园(第五本)・得胜令','王实甫','元','元曲','yuanqu','','[]','岂不闻"君子断具初"，我怎肯忘得有恩处？那一个贼畜生行嫉妒，走将来老夫人行厮间阻？不能够娇姝。',67,'元曲/yuanqu.json','["岂不闻\"君子断具初\"，我怎肯忘得有恩处？那一个贼畜生行嫉妒，走将来老夫人行厮间阻？不能够娇姝。", "早共晚施心数；说来的无徒，迟和疾上木驴。"]'),
('yuanqu-4193','张君瑞庆团园(第五本)・乔木查','王实甫','元','元曲','yuanqu','','[]','妾前来拜复，省可里心头怒！间别来安乐否？你那新夫人何处居？比俺姐姐是何如？(末云)和你也葫芦提了也。',82,'元曲/yuanqu.json','["妾前来拜复，省可里心头怒！间别来安乐否？你那新夫人何处居？比俺姐姐是何如？(末云)和你也葫芦提了也。", "小生为小姐受过的苦，诸人不知，瞒不得你。", "不甫能成亲，焉有是理？。"]'),
('yuanqu-4194','张君瑞庆团园(第五本)・沈醉东风','王实甫','元','元曲','yuanqu','','[]','不见时准备着千言万语，得相逢都变做短叹长吁。',66,'元曲/yuanqu.json','["不见时准备着千言万语，得相逢都变做短叹长吁。", "他急攘攘却才来，我羞答答怎生觑。", "将腹中愁恰待申诉，及至相逢一句也无。", "只道个\"先生万福\"。"]'),
('yuanqu-4195','张君瑞庆团园(第五本)・落梅风','王实甫','元','元曲','yuanqu','','[]','从离了蒲东路，来到京兆府，见个佳人世不留回顾。',51,'元曲/yuanqu.json','["从离了蒲东路，来到京兆府，见个佳人世不留回顾。", "硬揣个卫尚书家女孩儿为了眷属，曾见他影儿的也教灭门绝户。"]'),
('yuanqu-4196','张君瑞庆团园(第五本)・甜水令','王实甫','元','元曲','yuanqu','','[]','君瑞先生，不索踌躇。',50,'元曲/yuanqu.json','["君瑞先生，不索踌躇。", "何须忧虑。", "那厮本意糊涂；俺家世清白，祖宗贤良，相国名誉。", "我怎肯他跟前寄简传书？。"]'),
('yuanqu-4197','张君瑞庆团园(第五本)・雁儿落','王实甫','元','元曲','yuanqu','','[]','他曾笑孙庞真下愚，论贾马非英物；正授着征西元帅府，兼领着陕右河中路。',34,'元曲/yuanqu.json','["他曾笑孙庞真下愚，论贾马非英物；正授着征西元帅府，兼领着陕右河中路。"]'),
('yuanqu-4198','张君瑞庆团园(第五本)・得胜令','王实甫','元','元曲','yuanqu','','[]','是咱前者护身符，今日有权术。',53,'元曲/yuanqu.json','["是咱前者护身符，今日有权术。", "来时节定把先生助，决将贼子诛。", "他不识亲疏，嗓赚良人妇；你不辨贤愚，无毒不丈夫。"]'),
('yuanqu-4199','张君瑞庆团园(第五本)・落梅风','王实甫','元','元曲','yuanqu','','[]','你硬撞入桃源路，不言个谁是主，被东君把你个蜜蜂儿拦住。',51,'元曲/yuanqu.json','["你硬撞入桃源路，不言个谁是主，被东君把你个蜜蜂儿拦住。", "不信呵去那绿杨影里听杜宇，一声声道\"不如归去\"。"]'),
('yuanqu-4200','张君瑞庆团园(第五本)・沽美酒','王实甫','元','元曲','yuanqu','','[]','门迎着驷马车，户列着八椒图，娶了个四德三从宰相女，平生愿足，托赖着众亲故。',37,'元曲/yuanqu.json','["门迎着驷马车，户列着八椒图，娶了个四德三从宰相女，平生愿足，托赖着众亲故。"]'),
('yuanqu-4201','张君瑞庆团园(第五本)・太平令','王实甫','元','元曲','yuanqu','','[]','若不是大恩人拔刀相助，怎能够好夫妻似水如鱼。',55,'元曲/yuanqu.json','["若不是大恩人拔刀相助，怎能够好夫妻似水如鱼。", "得意也当时题柱，正酬了今生夫妇。", "自古、相女、配夫，新状元花生满路。"]'),
('yuanqu-4202','张君瑞庆团园(第五本)・锦上花','王实甫','元','元曲','yuanqu','','[]','四海无虞，皆称臣庶；诸国宋朝，万岁山呼；行迈羲轩，德过舜禹；圣策神机，仁文义武。',40,'元曲/yuanqu.json','["四海无虞，皆称臣庶；诸国宋朝，万岁山呼；行迈羲轩，德过舜禹；圣策神机，仁文义武。"]'),
('yuanqu-4203','张君瑞庆团园(第五本)・幺篇','王实甫','元','元曲','yuanqu','','[]','朝中宰相贤，天下庶民富，万里河清，五谷成熟；户户安居，处处乐土；凤凰来仪，麒麟屡出。',42,'元曲/yuanqu.json','["朝中宰相贤，天下庶民富，万里河清，五谷成熟；户户安居，处处乐土；凤凰来仪，麒麟屡出。"]'),
('yuanqu-4204','张君瑞庆团园(第五本)・清江引','王实甫','元','元曲','yuanqu','','[]','谢当今盛明唐圣主，敕赐为夫妇。',40,'元曲/yuanqu.json','["谢当今盛明唐圣主，敕赐为夫妇。", "永老无别离，万古常完聚，愿普天下有情的都成了眷属。"]'),
('yuanqu-4205','张君瑞庆团园(第五本)・随尾','王实甫','元','元曲','yuanqu','','[]','则因月底联诗句，成就了怨女旷夫。',36,'元曲/yuanqu.json','["则因月底联诗句，成就了怨女旷夫。", "显得有志的状元能，无情的郑恒苦。", "(下)。"]'),
('yuanqu-4206','中吕・上小楼客情','景元启','元','元曲','yuanqu','','[]','欲黄昏梅梢月明，动离愁酒阑人静。',62,'元曲/yuanqu.json','["欲黄昏梅梢月明，动离愁酒阑人静。", "则被他檐铁声寒，翠被难温，致令得倦客伤情。", "听山城，又起更，角声幽韵，想他绣帏中和我一般孤另。"]'),
('yuanqu-4207','双调・殿前欢自乐','景元启','元','元曲','yuanqu','','[]','自由仙，对西风篱下醉金船。',171,'元曲/yuanqu.json','["自由仙，对西风篱下醉金船。", "葛巾漉酒从吾愿，富贵由天。", "与渊明和一篇，君休羡，省部选乌台荐。", "好觑桐江钓叟，万古名传。", "自由仙，据胡床闲坐老梅边。", "彤云变态时舒卷，改尽山川。", "叹蓝关马不前，君休羡，八位转朝金殿。", "恰便似新晴雪霁，流水依然。", "梅花月如牙，早庭前疏影印窗纱。", "逃禅老笔应难画，别样清佳。", "据胡床再看咱，山妻骂：为甚情牵挂？大都来梅花是我，我是梅花。"]'),
('yuanqu-4208','双调・新水令','景元启','元','元曲','yuanqu','','[]','一春常费买花钱，锦营中惯曾游遍。',40,'元曲/yuanqu.json','["一春常费买花钱，锦营中惯曾游遍。", "酒斟金叵罗，人伴玉婵娟。", "急管繁弦，高楼上恣欢宴。"]'),
('yuanqu-4209','驻马听・骄马吟鞭，我是个酒社诗坛小状元。舞裙歌扇，伴着个风花雪月','景元启','元','元曲','yuanqu','','[]','玉天仙。',40,'元曲/yuanqu.json','["玉天仙。", "我把紫霜毫书满碧云笺，他撮着泥金袖绣彻红绒线。", "正当年，一团儿娇艳堪人羡。"]'),
('yuanqu-4211','川拨掉・拚了个吃昏拳，怕甚么咽顽涎。割舍了铜斗儿家缘，铁板儿似盘','景元启','元','元曲','yuanqu','','[]','便日用三千，我其实少不得个娇滴滴玉人儿过遣，怕的是独自眠。',29,'元曲/yuanqu.json','["便日用三千，我其实少不得个娇滴滴玉人儿过遣，怕的是独自眠。"]'),
('yuanqu-4212','七弟兄・我这里告天：可怜，教我永团圆！原天公与我行方便，地连枝产','景元启','元','元曲','yuanqu','','[]','朵并头连，天比翼生对双飞燕。',14,'元曲/yuanqu.json','["朵并头连，天比翼生对双飞燕。"]'),
('yuanqu-4213','梅花酒・到春来景物妍，簪杏鬟鬟蝉，拾翠步金莲，听鸟并香肩。到夏来','景元启','元','元曲','yuanqu','','[]','携手上采莲船，瓜初剖水晶丸，酒新泛蓿砂煎，鱼旋打锦鳞鲜。',28,'元曲/yuanqu.json','["携手上采莲船，瓜初剖水晶丸，酒新泛蓿砂煎，鱼旋打锦鳞鲜。"]'),
('yuanqu-4214','收江南・呀！到秋来看四围红叶满山川，两行翠袖画堂前，看一轮明月照','景元启','元','元曲','yuanqu','','[]','天边。',21,'元曲/yuanqu.json','["天边。", "到冬来雪花儿满天，蒸羊羔美酒庆丰年。"]'),
('yuanqu-4215','尾声・四时独占风流选，百年遂却于飞愿。常言道女貌郎才，恨惹情牵。','景元启','元','元曲','yuanqu','','[]','将一对美满姻缘，万载千秋教人做笑话儿演。',20,'元曲/yuanqu.json','["将一对美满姻缘，万载千秋教人做笑话儿演。"]'),
('yuanqu-4216','越调・天净沙','严忠济','元','元曲','yuanqu','','[]','宁可少活十年，休得一日无权，大丈夫时乘命蹇。',39,'元曲/yuanqu.json','["宁可少活十年，休得一日无权，大丈夫时乘命蹇。", "有朝一日天随人愿，赛田文养客三千。"]'),
('yuanqu-4217','双调・寿阳曲','严忠济','元','元曲','yuanqu','','[]','三闾些，伍子歌，利名阳几人参破？算来都不如蓝采和，被这几文钱把这小儿瞒过。',37,'元曲/yuanqu.json','["三闾些，伍子歌，利名阳几人参破？算来都不如蓝采和，被这几文钱把这小儿瞒过。"]'),
('yuanqu-4218','双调・蟾宫曲','汤舜民','元','元曲','yuanqu','','[]','冷清清人在西厢，叫一声张郎，骂一声张郎。',98,'元曲/yuanqu.json','["冷清清人在西厢，叫一声张郎，骂一声张郎。", "乱纷纷花落东墙，问一会红娘絮一会红娘。", "枕儿余，衾儿剩，温一半绣床，间一半绣床。", "月儿斜，风儿细开一扇纱窗，掩一扇抄窗。", "荡悠悠梦绕高唐，萦一寸柔肠，断一寸柔肠。"]'),
('yuanqu-4219','双调・湘妃游月宫春闺情','汤舜民','元','元曲','yuanqu','','[]','海棠过雨绵狼藉，杨柳团烟青旖旎，梨化滴露珠零碎。',524,'元曲/yuanqu.json','["海棠过雨绵狼藉，杨柳团烟青旖旎，梨化滴露珠零碎。", "春深也人未归，对东风满目伤悲。", "近绿窗蜂喧蝶闹，临宝镜鸾愁凤泣，隔珠帘燕语莺啼。", "隔珠帘燕语莺啼，莺呖呖如诉凄凉。", "燕喃喃似说别离。", "香魂趁飞絮悠扬，薄命逐游丝飘荡，芳心随落日昏迷。", "三分病积渐里消磨了玉肌，一春愁积攒下压损了蛾眉。", "愁和病最苦禁持，靠银床倦眼乜斜，湿金衣清泪淋漓。", "夏闺情冰盘贮果水晶凉，石髓和茶玉液香，碧筒注饮葡萄酿。", "伤心也谁共赏，对良宵无限凄凉。", "藕花风轻翻纱帐，杨柳月微笼绣窗，梧桐露响滴银床。", "梧桐露响滴银床，脚步儿未离南轩，魂灵儿已到东墙。", "屏闲也翡翠蒙尘，簟冷也琉璃失色，枕空也琥珀无光。", "谁承望生折了连枝树上凤凰，不提防活刺了并头花底鸳鸯。", "尽今生难舍难忘。", "甜腻腻两字恩情，苦恹恹几样思量。", "秋闺情绣帏冷落采绒球，珠箔空闲碧玉钩，罗衣宽褪泥金扣。", "恹恹不下楼，对西凤总是离愁。", "孤鹜点白云天际，新雁过黄芦渡口，昏鸦啼红树墙头。", "昏鸦啼红树墙头，透疏帘凉月纤纤，走空阶落叶飕飕。", "难支吾今夜寂寥，索准备经年憔悴。", "漫咨嗟往日风流，落下个玉镜台不成配偶，谅这个紫香囊怎做遗留？细评跋着甚来由，遥受的凤友鸾交，虚名儿燕侣莺俦。", "冬闺情鬓从别后甚蓬松，心自愁添越懵懂，肠于断处偏疼痛。", "更难捱寒夜永，树梅花欢笑谁同。"]'),
('yuanqu-4220','正宫・小梁州别情代人作其人姓刘','汤舜民','元','元曲','yuanqu','','[]','晚妆楼上醉离觞，月色苍苍。',31,'元曲/yuanqu.json','["晚妆楼上醉离觞，月色苍苍。", "来时何暮去何忙，空惆怅，无计锁鸳鸯。"]'),
('yuanqu-4221','・残云剩雨阳台上，空赢得两袖余香。则恐怕春夜长，东风壮，桃花飘荡，何处','汤舜民','元','元曲','yuanqu','','[]','幺觅刘郎？九日渡江二首秋风江上棹孤舟，烟水悠悠。',42,'元曲/yuanqu.json','["幺觅刘郎？九日渡江二首秋风江上棹孤舟，烟水悠悠。", "伤心无句赋登楼，山容瘦，老树替人愁。"]'),
('yuanqu-4222','・樽前醉把茱萸嗅，问相知几个白头。乐可酬，人非旧，黄花时候，难比旧风流。','汤舜民','元','元曲','yuanqu','','[]','幺秋风江上棹孤航，烟水茫茫。',32,'元曲/yuanqu.json','["幺秋风江上棹孤航，烟水茫茫。", "白云西去雁南翔，推篷望，清思满沧浪。"]'),
('yuanqu-4223','幺・东','汤舜民','元','元曲','yuanqu','','[]','篱载酒陶元亮，等档间过了重阳。',73,'元曲/yuanqu.json','["篱载酒陶元亮，等档间过了重阳。", "自感伤。", "何情况，黄花惆怅，空作去年香。", "扬子江阻风篷窗风急雨丝丝，闷捻吟髭。", "维扬西望渺何之？无一个鸿鳞至，把酒问篙师。"]'),
('yuanqu-4224','幺・他迎头儿便说干戈事，待风流再莫追思。塌了酒楼，焚了茶肆，柳营花市，','汤舜民','元','元曲','yuanqu','','[]','更说甚呼燕子唤莺儿。',45,'元曲/yuanqu.json','["更说甚呼燕子唤莺儿。", "代人寄情花下清歌月下弹，意惹情关。", "颠鸾倒凤数十番，从分散，情意便阑珊。"]'),
('yuanqu-4225','・登临未了斜阳暗，借白云半榻禅龛。发笑谈，论经谶，老龙惊惮，拖雨过江南。咏雪效苏禁体作','汤舜民','元','元曲','yuanqu','','[]','幺天低风静日昏昏，一片同云。',32,'元曲/yuanqu.json','["幺天低风静日昏昏，一片同云。", "穿帘透暮舞纷纷，寒成阵，则索闭柴门。"]'),
('yuanqu-4226','・陶学士满口誉清俊，邮亭中冻得来伤神，颠倒说老党村。诸般□，羊羔美耐，','汤舜民','元','元曲','yuanqu','','[]','幺金帐里醉醺醺。',39,'元曲/yuanqu.json','["幺金帐里醉醺醺。", "黄昏微雨净尘沙，飞尽归鸦。", "斜飘乱撒扑窗纱，迷鸳瓦，一色净无瑕。"]'),
('yuanqu-4227','幺・棱棱衾铁萧萧塌，问羊羔那里寻他。不由人狂兴发，把扁舟驾，向','汤舜民','元','元曲','yuanqu','','[]','山阴直下，认不得戴逵家。',49,'元曲/yuanqu.json','["山阴直下，认不得戴逵家。", "太真开元天子好奢华，太真妃选作浑家。", "东风吹动祸根芽，娘牵挂，没乱煞胖娃娃。"]'),
('yuanqu-4228','幺・不提防变却承平卦，闹渔阳一片胡笳。辞风榻，迁鸾驾，马嵬坡下，','汤舜民','元','元曲','yuanqu','','[]','踏碎海棠花。',42,'元曲/yuanqu.json','["踏碎海棠花。", "丽华临风阁内俏人儿，天生得玉骨冰姿。", "承欢奉喜度芳时，多才思，举笔便题诗。"]'),
('yuanqu-4229','幺・谁承望擒虎将军至，拥貔貅百万雄师。惊散了玉树歌，推上云阳市。黄天','汤舜民','元','元曲','yuanqu','','[]','何事，流泪洒胭脂。',9,'元曲/yuanqu.json','["何事，流泪洒胭脂。"]'),
('yuanqu-4230','正宫・脱布衫带小梁州四景为储公子赋凤阳人春','汤舜民','元','元曲','yuanqu','','[]','问春来何处忘机？小奚奴相趁相随。',68,'元曲/yuanqu.json','["问春来何处忘机？小奚奴相趁相随。", "傍柳行乌纱翠湿，踏花去马蹄香细。", "翠幄银屏锦绣围，莫放春归。", "人生七十古来稀，便做道一百岁，能几度醉如泥！。"]'),
('yuanqu-4231','幺・韶华迅速难拘系，杜鹃声只在楼西。北海樽，东山妓。春风天地，何','汤舜民','元','元曲','yuanqu','','[]','日不寒夜。',69,'元曲/yuanqu.json','["日不寒夜。", "夏问夏来何处徜徉？闲遥遥傲煞羲皇。", "啜□碗清冰蔗浆，卧藤簟翠ブ绡帐。", "细柳垂丝过粉墙，满地清凉。", "金河流水玉莲香，微风荡，香满看书窗。"]'),
('yuanqu-4232','・亭台净扫无纤垢，胜当年庚亮南楼。传画烛，焚金兽。碧天如昼，今夜赏中秋。冬','汤舜民','元','元曲','yuanqu','','[]','幺问冬来何处从容？千金裘五彩蒙茸。',64,'元曲/yuanqu.json','["幺问冬来何处从容？千金裘五彩蒙茸。", "鱼游锦重衾密拥，驼绒毡软帘低控。", "揽碎银河战玉龙。", "鳞甲琮琮。", "楼台上下水晶宫，堪题咏，人在画图中。"]'),
('yuanqu-4234','越调・柳营曲途中春暮','汤舜民','元','元曲','yuanqu','','[]','岐路北，断桥西，滴溜溜酒帘茅舍低。',347,'元曲/yuanqu.json','["岐路北，断桥西，滴溜溜酒帘茅舍低。", "柳暗疏篱，水浸平堤，仿佛旧山溪。", "车儿马儿奔驰，莺儿燕儿悲啼。", "帽沾飞絮寻，衣染落花泥。", "知，何处度寒食？旅次归路杳，去程遥，谁不恋故乡生处好。", "粝饭薄醪，野蔌山肴，随发度昏朝。", "隔篱度犬嗷嗷，投林倦鸟嘈嘈。", "烟霞云黯淡，风雨夜萧骚。", "纱窗外有芭蕉。", "春思鸦髻松，凤钗横，碧窗梦回春昼永。", "离绪蒙茸，倦眼朦胧，清泪滴香容。", "恨东君多雨多风，盼王孙无影无踪。", "柳添新样绿，花减旧时红。", "尽在不言中。", "薛琼琼弹筝图玉雪颜，翠云鬟，昭阳殿里醉了几番。", "金袖翩翩，银甲珊珊，记天宝年间。", "哄的兵散潼关，忽的尘暗长安。", "风云都变改，日月自循环。", "闲，写作画图看。", "听筝酒乍醒，月初明，谁家小楼调玉筝？指拨轻清，音律和平，一字字诉衷情。", "恰流莺花底叮咛，又孤鸿云外悲鸣。", "滴碎金砌雨，敲碎玉壶冰。", "听，尽是断肠声。"]'),
('yuanqu-4235','黄钟・山队子酒色财气四首','汤舜民','元','元曲','yuanqu','','[]','曲生堪爱，晕桃花上脸腮。',175,'元曲/yuanqu.json','["曲生堪爱，晕桃花上脸腮。", "百篇一斗恣开怀，谁承望捉月骑鲸再不来。", "酒，则被你断送了文章李太白。", "怜香惜玉，醉临春欢未足。", "开皇戈甲出江都，惊散金钗玉树曲。", "色，则被你断送了聪明陈后主。", "钱神涌论，亻赞家私多误身。", "东风吹堕画楼人，一夜香消金谷春。", "财，则被你断送了奢华石季伦。", "图王争帝，半乾坤心未已。", "鸿门会上失兵机，直杀得血溅阴陵后悔迟。", "气，则为你断送了英雄楚项籍。"]'),
('yuanqu-4236','双调・鸿门凯歌□□','汤舜民','元','元曲','yuanqu','','[]','□□□□□□□□□□□□□□□□□□□□□□□□□蓍。',65,'元曲/yuanqu.json','["□□□□□□□□□□□□□□□□□□□□□□□□□蓍。", "离纟乱荡□丝纟虫□纟夜孤鸾吊景□嗟宫好梦儿成亻□事。", "相思，痴心直到死。", "套数。"]'),
('yuanqu-4237','双调・新水令春日闺思','汤舜民','元','元曲','yuanqu','','[]','一帘飞絮滚凤团，启朱扉眼花撩乱。',40,'元曲/yuanqu.json','["一帘飞絮滚凤团，启朱扉眼花撩乱。", "腕消金钏松，腰瘦翠裙宽。", "独步盘桓，幽窗下画栏畔。"]'),
('yuanqu-4238','驻马听・妆点幽欢，凤髓茶温白玉碗；安排佳玩，龙涎香袅紫金盘。琼花','汤舜民','元','元曲','yuanqu','','[]','露点滴水晶丸，荔枝浆荡漾玻璃罐。',34,'元曲/yuanqu.json','["露点滴水晶丸，荔枝浆荡漾玻璃罐。", "日光酣，天气暖，牡丹风吹不到芙蓉幔。"]'),
('yuanqu-4239','鸿门凯歌・冷淡了联珠翡翠冠，离披了合彩鸳鸯段，零落了回文龟背锦，','汤舜民','元','元曲','yuanqu','','[]','空闲了通宝鸦青幔，巫山庙云壑翠Лヴ桃源洞烟火黑弥漫，望夫台景物年年在，相思海风波日日满。',66,'元曲/yuanqu.json','["空闲了通宝鸦青幔，巫山庙云壑翠Лヴ桃源洞烟火黑弥漫，望夫台景物年年在，相思海风波日日满。", "眉攒，屈纤指把归期算；心酸，染霜毫将离恨纂。"]'),
('yuanqu-4240','甜水令・空撇下乡幕房栊，银烛帏屏，珠帘楼观，几度月团圆。斗草无心，','汤舜民','元','元曲','yuanqu','','[]','待月无情，吹箫无伴，眼睁睁寡凤孤鸾。',18,'元曲/yuanqu.json','["待月无情，吹箫无伴，眼睁睁寡凤孤鸾。"]'),
('yuanqu-4241','随煞・多应是在谁家风月闲亭馆，陡恁的情悭义短。我ゐ惶事攒下万千般，','汤舜民','元','元曲','yuanqu','','[]','他风流罪攒来数十款。',57,'元曲/yuanqu.json','["他风流罪攒来数十款。", "送王姬往钱塘十年无梦到京师，卧书窗坦然如是。", "几偿沽酒债，填不满买花资。", "近柳题诗，又感起少年事。"]'),
('yuanqu-4242','驻马听・槁木船容姿，对花月羞斟鹦鹉卮。浮云般神思，扭宫商强作鹧鸪','汤舜民','元','元曲','yuanqu','','[]','我吟到碧梧栖老凤凰枝，他道是雕笼锁定鸳鸯翅。',43,'元曲/yuanqu.json','["我吟到碧梧栖老凤凰枝，他道是雕笼锁定鸳鸯翅。", "急煎煎捻断吟髭，则被你紫云娘奚落杀白衣士。"]'),
('yuanqu-4243','沉醉东风・讲礼教虚心儿拜辞，说艰难满口儿嗟咨。蛾眉浅黛颦，花靥啼','汤舜民','元','元曲','yuanqu','','[]','红渍，向樽前留下些相思。',29,'元曲/yuanqu.json','["红渍，向樽前留下些相思。", "我本是当年杜牧之，休认做苏州剌史。"]'),
('yuanqu-4244','庆东原・雨歇阳关至，草生南浦时，好山一路相随侍。沉点点莺花担儿，','汤舜民','元','元曲','yuanqu','','[]','稳拍拍的花藤轿儿，嗑刺刺鹿顶车儿。',29,'元曲/yuanqu.json','["稳拍拍的花藤轿儿，嗑刺刺鹿顶车儿。", "踅过若耶溪，赶上钱塘市。"]'),
('yuanqu-4245','离亭宴歇指煞・我不向风流选内求咨示，谁承望别离卷上题名字，关心为','汤舜民','元','元曲','yuanqu','','[]','慢教蜂做问花媒，不劳莺唤寻芳友，何须蝶做追香使。',145,'元曲/yuanqu.json','["慢教蜂做问花媒，不劳莺唤寻芳友，何须蝶做追香使。", "春残小洞房，门掩闲构肆，不是我愁红怨紫。", "青楼赢的姓名留，彩云渐逐箫声去，锦鳞拟待音书至。", "明牵双渐情，暗隐江淹志。", "多娇鉴兹，搜锦绣九回肠，扫云烟半张纸。", "秋夜梦回有感凤台无伴吕鸾箫，间别来未知音耗。", "鱼沉尺素稀，雁断锦笺遥。", "魄散魂消，心间事对谁道。"]'),
('yuanqu-4246','驻马听・林外萧条，一夜霜侵红叶老。庭前寂寥，几番风撼的碧梧雕。病','汤舜民','元','元曲','yuanqu','','[]','儿多偏觉被儿薄。',30,'元曲/yuanqu.json','["儿多偏觉被儿薄。", "影儿孤最怕灯儿照。", "睡不着，淅零零暮雨窗前哨。"]'),
('yuanqu-4248','沉醉东风・则见他乌云髻斜簪玉翘，芙蓉额檀口似樱桃。端的是万种娇，','汤舜民','元','元曲','yuanqu','','[]','千般俏，更那堪兰麝香飘。',34,'元曲/yuanqu.json','["千般俏，更那堪兰麝香飘。", "今日个得见多情女艳娇，将我这受过的凄凉忘了。"]'),
